  1→import { stat } from 'node:fs/promises';
  2→import { ClaudeAgent } from '../agents/claude/claude-agent.ts';
  3→import type { LineParser } from '../agents/agent.interface.ts';
  4→import type { Formatter } from '../formatters/formatter.interface.ts';
  5→import type { ParsedLine, SessionFile } from '../core/types.ts';
  6→import {
  7→  type SubagentDetector,
  8→  MAIN_LABEL,
  9→  buildSubagentPath,
 10→} from './subagent-detector.ts';
 11→
 12→export const SUPER_FOLLOW_POLL_MS = 500;
 13→export const SUPER_FOLLOW_DELAY_MS = 5000;
 14→
 15→/**
 16→ * 從 subagent JSONL 檔案讀取最後一條 assistant 訊息的所有 ParsedLine parts
 17→ * 用於在 pane 關閉前回顯 subagent 的最終報告
 18→ */
 19→export async function readLastAssistantMessage(
 20→  filePath: string,
 21→  verbose: boolean
 22→): Promise<ParsedLine[]> {
 23→  try {
 24→    const file = Bun.file(filePath);
 25→    if (!(await file.exists())) return [];
 26→
 27→    const content = await file.text();
 28→    const lines = content.split('\n').filter(Boolean);
 29→
 30→    // 從尾部往前找最後一條 type === 'assistant' 的行
 31→    let lastAssistantLine: string | null = null;
 32→    for (let i = lines.length - 1; i >= 0; i--) {
 33→      const line = lines[i]!;
 34→      try {
 35→        const data = JSON.parse(line);
 36→        if (data.type === 'assistant') {
 37→          lastAssistantLine = line;
 38→          break;
 39→        }
 40→      } catch {
 41→        // 略過無效 JSON
 42→      }
 43→    }
 44→
 45→    if (!lastAssistantLine) return [];
 46→
 47→    // 用新的 parser 實例解析（避免狀態污染）
 48→    const parser = new ClaudeAgent({ verbose }).parser;
 49→    const parts: ParsedLine[] = [];
 50→    let parsed = parser.parse(lastAssistantLine);
 51→    while (parsed) {
 52→      parts.push(parsed);
 53→      parsed = parser.parse(lastAssistantLine);
 54→    }
 55→
 56→    return parts;
 57→  } catch {
 58→    return [];
 59→  }
 60→}
 61→
 62→/**
 63→ * 掃描 subagents 目錄，取得現有 subagent 檔案並按 birthtime 升序排序
 64→ */
 65→export async function buildSubagentFiles(
 66→  subagentsDir: string,
 67→  initialAgentIds: Set<string>
 68→): Promise<Array<{ agentId: string; path: string; birthtime: Date }>> {
 69→  // 平行化 stat 呼叫，直接用 stat() 取代 exists() + stat() 的雙重 syscall
 70→  const results = await Promise.all(
 71→    [...initialAgentIds].map(async (agentId) => {
 72→      const subagentPath = buildSubagentPath(subagentsDir, agentId);
 73→      try {
 74→        const stats = await stat(subagentPath);
 75→        return { agentId, path: subagentPath, birthtime: stats.birthtime };
 76→      } catch {
 77→        // 檔案不存在（ENOENT）或無法存取，跳過
 78→        return null;
 79→      }
 80→    })
 81→  );
 82→
 83→  // 過濾掉不存在的檔案，按建立時間升序排序（最舊的先加入）
 84→  return results
 85→    .filter(
 86→      (r): r is { agentId: string; path: string; birthtime: Date } => r !== null
 87→    )
 88→    .sort((a, b) => a.birthtime.getTime() - b.birthtime.getTime());
 89→}
