 91→/**
 92→ * createOnLineHandler 的配置
 93→ */
 94→export interface OnLineHandlerConfig {
 95→  parsers: Map<string, LineParser>;
 96→  formatter: Formatter;
 97→  detector: SubagentDetector;
 98→  onOutput: (formatted: string, label: string) => void;
 99→  verbose: boolean;
100→  /** 過濾函數：回傳 true 表示應該輸出，false 表示跳過（Phase 2.3） */
101→  shouldOutput?: (label: string) => boolean;
102→  /** Callback when a custom-title event is detected on MAIN session */
103→  onTitleUpdate?: (title: string) => void;
104→}
105→
106→/**
107→ * 建立標準 onLine handler，供 MultiFileWatcher 的 onLine callback 使用
108→ */
109→export function createOnLineHandler(
110→  config: OnLineHandlerConfig
111→): (line: string, label: string) => void {
112→  return (line: string, label: string) => {
113→    // agent_progress：subagent 進入或 resume，每次進入都觸發 pane 開啟
114→    // 前置字串檢查避免每行都 JSON.parse（熱路徑優化）
115→    if (label === MAIN_LABEL && line.includes('"agent_progress"')) {
116→      try {
117→        const data = JSON.parse(line) as {
118→          type?: string;
119→          data?: { type?: string; agentId?: string };
120→        };
121→        if (
122→          data.type === 'progress' &&
123→          data.data?.type === 'agent_progress' &&
124→          data.data?.agentId
125→        ) {
126→          config.detector.handleAgentProgress(data.data.agentId);
127→        }
128→      } catch {
129→        // 非 JSON 或無關格式，略過
130→      }
131→    }
132→
133→    let parser = config.parsers.get(label);
134→    if (!parser) {
135→      const newAgent = new ClaudeAgent({ verbose: config.verbose });
136→      parser = newAgent.parser;
137→      config.parsers.set(label, parser);
138→    }
139→
140→    let parsed = parser.parse(line);
141→    while (parsed) {
142→      parsed.sourceLabel = label;
143→
144→      // Phase 2.3: 過濾已有 pane 的 subagent 輸出
145→      if (config.shouldOutput && !config.shouldOutput(label)) {
146→        parsed = parser.parse(line);
147→        continue;
148→      }
149→
150→      config.onOutput(config.formatter.format(parsed), label);
151→
152→      // Real-time custom-title update
153→      if (
154→        label === MAIN_LABEL &&
155→        parsed.isCustomTitle &&
156→        parsed.customTitleValue
157→      ) {
158→        config.onTitleUpdate?.(parsed.customTitleValue);
159→      }
160→
161→      // 早期 Subagent 偵測：當偵測到 Task tool_use 時立即掃描
162→      if (label === MAIN_LABEL && parsed.isTaskToolUse) {
163→        // Push description before early detection so it's queued when scan triggers
164→        if (parsed.taskDescription) {
165→          config.detector.pushDescription(parsed.taskDescription);
166→        }
167→        config.detector.handleEarlyDetection();
168→      }
169→
170→      // 備援機制：從主 session 的 toolUseResult 檢查新 subagent
171→      if (label === MAIN_LABEL) {
172→        const raw = parsed.raw as {
173→          toolUseResult?: {
174→            agentId?: string;
175→            commandName?: string;
176→            status?: string;
177→          };
178→        };
179→        const agentId = raw?.toolUseResult?.agentId;
180→        const commandName = raw?.toolUseResult?.commandName;
181→        const status = raw?.toolUseResult?.status;
182→
183→        if (agentId && !commandName && status !== 'forked') {
184→          config.detector.handleFallbackDetection(agentId);
185→        }
186→      }
187→
188→      parsed = parser.parse(line);
189→    }
190→  };
191→}
