 15→const CODEX_UUID_IN_PATH =
 16→  /([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})\.jsonl$/i;
 17→
 18→/** 從 rollout-*.jsonl 路徑中提取 UUID */
 19→export function extractUUIDFromPath(filePath: string): string {
 20→  return filePath.match(CODEX_UUID_IN_PATH)?.[1] ?? '';
 21→}
