578→/**
579→ * 時間排序輸出（用於 --no-follow --with-subagents 模式）
580→ * 收集所有檔案的行，按時間戳排序後輸出
581→ */
582→async function outputTimeSorted(
583→  files: WatchedFile[],
584→  parsers: Map<string, LineParser>,
585→  formatter: Formatter,
586→  _options: CliOptions
587→): Promise<void> {
588→  // 收集所有已解析的行
589→  const allParsedLines: Array<{
590→    parsed: import('./core/types.ts').ParsedLine;
591→    timestamp: Date;
592→  }> = [];
593→
594→  for (const file of files) {
595→    const parser = parsers.get(file.label);
596→    if (!parser) continue;
597→
598→    // 讀取檔案內容
599→    const bunFile = Bun.file(file.path);
600→    if (!(await bunFile.exists())) continue;
601→
602→    const content = await bunFile.text();
603→    const lines = content.split('\n').filter((line) => line.trim());
604→
605→    for (const line of lines) {
606→      let parsed = parser.parse(line);
607→      while (parsed) {
608→        parsed.sourceLabel = file.label;
609→        allParsedLines.push({
610→          parsed,
611→          timestamp: new Date(parsed.timestamp),
612→        });
613→        parsed = parser.parse(line);
614→      }
615→    }
616→  }
617→
618→  // 按時間戳排序（舊到新）
619→  allParsedLines.sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());
620→
621→  // 依序輸出
622→  for (const { parsed } of allParsedLines) {
623→    console.log(formatter.format(parsed));
624→  }
625→}
