272→/**
273→ * 從文字中去除 <user_query> 包裝標籤
274→ */
275→function stripUserQueryTags(text: string): string {
276→  return text
277→    .replace(/^<user_query>\s*/s, '')
278→    .replace(/\s*<\/user_query>\s*$/s, '')
279→    .trim();
280→}
281→
282→/**
283→ * 從文字中去除 <attached_files> 區塊
284→ */
285→function stripAttachedFilesTags(text: string): string {
286→  return text.replace(/<attached_files>[\s\S]*?<\/attached_files>/g, '').trim();
287→}
288→
289→/**
290→ * Cursor JSONL 解析器（無狀態）
291→ * 格式: {"role":"user|assistant","message":{"content":[{"type":"text","text":"..."}]}}
292→ */
293→class CursorLineParser implements LineParser {
294→  private verbose: boolean;
295→
296→  constructor(options: ParserOptions = { verbose: false }) {
297→    this.verbose = options.verbose;
298→  }
299→
300→  parse(line: string): ParsedLine | null {
301→    if (!line.trim()) return null;
302→
303→    try {
304→      const data = JSON.parse(line);
305→      const role = data.role as string;
306→      if (!role) return null;
307→
308→      const content = data.message?.content;
309→      let text = contentToString(content);
310→
311→      if (!text.trim()) return null;
312→
313→      // 清除包裝標籤（先移除 attached_files 區塊，再移除 user_query 標籤）
314→      // 順序重要：attached_files 可能在 user_query 之前，必須先清除才能讓 user_query 的 ^ 錨點匹配
315→      if (role === 'user') {
316→        text = stripAttachedFilesTags(text);
317→        text = stripUserQueryTags(text);
318→      }
319→
320→      if (!text.trim()) return null;
321→
322→      const preview = truncateByLines(text, { verbose: this.verbose });
323→
324→      return {
325→        type: role, // 'user' | 'assistant' — PrettyFormatter 已支援
326→        timestamp: '', // Cursor 日誌無時間戳
327→        raw: data,
328→        formatted: formatMultiline(preview),
329→      };
330→    } catch {
331→      return null;
332→    }
333→  }
334→}
