 69→export function parseArgs(args: string[]): CliOptions {
 70→  const program = createProgram();
 71→  program.parse(args);
 72→
 73→  const agentTypeArg = program.args[0];
 74→  const sessionIdArg = program.args[1];
 75→  const opts = program.opts();
 76→
 77→  // 驗證 agent 類型
 78→  if (
 79→    agentTypeArg !== 'codex' &&
 80→    agentTypeArg !== 'claude' &&
 81→    agentTypeArg !== 'gemini' &&
 82→    agentTypeArg !== 'cursor'
 83→  ) {
 84→    console.error(
 85→      `Error: Invalid agent type "${agentTypeArg}". Use "codex", "claude", "gemini", or "cursor".`
 86→    );
 87→    process.exit(1);
 88→  }
 89→
 90→  // subagent 選項對 claude 和 codex 有效
 91→  if (
 92→    opts.subagent !== undefined &&
 93→    agentTypeArg !== 'claude' &&
 94→    agentTypeArg !== 'codex'
 95→  ) {
 96→    console.error(
 97→      'Error: --subagent option is only available for "claude" and "codex" agent types.'
 98→    );
 99→    process.exit(1);
100→  }
101→
102→  // --all preset 選項對 claude 和 codex 有效（需要在展開前驗證）
103→  if (opts.all && agentTypeArg !== 'claude' && agentTypeArg !== 'codex') {
104→    console.error(
105→      'Error: --all option is only available for "claude" and "codex" agent types.'
106→    );
107→    process.exit(1);
108→  }
109→
110→  // 展開 --all preset（只在選項未明確設定時才覆蓋）
111→  if (opts.all) {
112→    if (opts.verbose === undefined) opts.verbose = true;
113→    if (opts.withSubagents === undefined) opts.withSubagents = true;
114→    if (opts.autoSwitch === undefined) opts.autoSwitch = true;
115→  }
116→
117→  // 將 undefined 轉換為 false（對於非 preset 選項）
118→  const finalVerbose = opts.verbose ?? false;
119→  const finalInteractive = opts.interactive ?? false;
120→  let finalWithSubagents = opts.withSubagents ?? false;
121→  const finalAutoSwitch = opts.autoSwitch ?? false;
122→  const finalPane = opts.pane ?? false;
123→
124→  // interactive 選項對 claude 和 codex 有效
125→  if (
126→    finalInteractive &&
127→    agentTypeArg !== 'claude' &&
128→    agentTypeArg !== 'codex'
129→  ) {
130→    console.error(
131→      'Error: --interactive option is only available for "claude" and "codex" agent types.'
132→    );
133→    process.exit(1);
134→  }
135→
136→  // interactive 和 subagent 互斥
137→  if (finalInteractive && opts.subagent !== undefined) {
138→    console.error(
139→      'Error: --interactive and --subagent options cannot be used together.'
140→    );
141→    process.exit(1);
142→  }
143→
144→  // interactive 需要 follow 模式
145→  if (finalInteractive && !opts.follow) {
146→    console.error(
147→      'Error: --interactive requires --follow mode (cannot use with --no-follow).'
148→    );
149→    process.exit(1);
150→  }
151→
152→  // pane 選項對 claude 和 codex 有效
153→  if (finalPane && agentTypeArg !== 'claude' && agentTypeArg !== 'codex') {
154→    console.error(
155→      'Error: --pane option is only available for "claude" and "codex" agent types.'
156→    );
157→    process.exit(1);
158→  }
159→
160→  // pane 和 interactive 互斥
161→  if (finalPane && finalInteractive) {
162→    console.error(
163→      'Error: --pane and --interactive options cannot be used together.'
164→    );
165→    process.exit(1);
166→  }
167→
168→  // pane 和 subagent 互斥（pane 在多檔案監控模式，subagent 在單檔案模式）
169→  if (finalPane && opts.subagent !== undefined) {
170→    console.error(
171→      'Error: --pane and --subagent options cannot be used together.'
172→    );
173→    process.exit(1);
174→  }
175→
176→  // pane 需要 follow 模式
177→  if (finalPane && !opts.follow) {
178→    console.error(
179→      'Error: --pane requires --follow mode (cannot use with --no-follow).'
180→    );
181→    process.exit(1);
182→  }
183→
184→  // pane 自動啟用 withSubagents（subagent 偵測必須啟用才能開 pane）
185→  if (finalPane && !finalWithSubagents) {
186→    finalWithSubagents = true;
187→  }
188→
189→  // withSubagents 選項對 claude 和 codex 有效
190→  if (
191→    finalWithSubagents &&
192→    agentTypeArg !== 'claude' &&
193→    agentTypeArg !== 'codex'
194→  ) {
195→    console.error(
196→      'Error: --with-subagents option is only available for "claude" and "codex" agent types.'
197→    );
198→    process.exit(1);
199→  }
200→
201→  // sleepInterval 驗證
202→  if (
203→    opts.sleepInterval !== undefined &&
204→    (opts.sleepInterval < 100 || opts.sleepInterval > 60000)
205→  ) {
206→    console.error(
207→      'Error: --sleep-interval must be between 100 and 60000 milliseconds.'
208→    );
209→    process.exit(1);
210→  }
211→
212→  // lines 驗證
213→  if (opts.lines !== undefined && Number.isNaN(opts.lines)) {
214→    console.error('Error: --lines must be a valid number.');
215→    process.exit(1);
216→  }
217→
218→  return {
219→    agentType: agentTypeArg as AgentType,
220→    raw: opts.raw,
221→    project: opts.project,
222→    follow: opts.follow,
223→    verbose: finalVerbose,
224→    quiet: opts.quiet ?? false,
225→    sleepInterval: opts.sleepInterval ?? 500,
226→    lines: opts.lines,
227→    subagent: opts.subagent,
228→    interactive: finalInteractive,
229→    withSubagents: finalWithSubagents,
230→    autoSwitch: finalAutoSwitch,
231→    pane: finalPane,
232→    sessionId: sessionIdArg,
233→  };
234→}
