 1→import { FileWatcher, type WatchOptions } from './file-watcher.ts';
 2→
 3→/**
 4→ * 要監控的檔案資訊
 5→ */
 6→export interface WatchedFile {
 7→  path: string;
 8→  label: string; // "[MAIN]" 或 "[agentId]"
 9→}
10→
11→/**
12→ * 多檔案監控選項
13→ */
14→export interface MultiWatchOptions extends Omit<WatchOptions, 'onLine'> {
15→  onLine: (line: string, label: string) => void;
16→  onNewFile?: (file: WatchedFile) => void;
17→}
18→
19→/**
20→ * 多檔案監控器 - 管理多個 FileWatcher 實例
21→ */
22→export class MultiFileWatcher {
23→  private watchers: Map<string, FileWatcher> = new Map();
24→  private options: MultiWatchOptions | null = null;
25→
26→  /**
27→   * 開始監控多個檔案
28→   */
29→  async start(files: WatchedFile[], options: MultiWatchOptions): Promise<void> {
30→    this.options = options;
31→
32→    // 為每個檔案建立獨立的 FileWatcher
33→    for (const file of files) {
34→      await this.addFile(file);
35→    }
36→  }
37→
38→  /**
39→   * 新增監控檔案
40→   */
41→  async addFile(file: WatchedFile): Promise<void> {
42→    if (this.watchers.has(file.path)) return;
43→    if (!this.options) return;
44→
45→    const watcher = new FileWatcher();
46→    this.watchers.set(file.path, watcher);
47→
48→    const { onLine, onNewFile: _onNewFile, ...restOptions } = this.options;
49→    await watcher.start(file.path, {
50→      ...restOptions,
51→      onLine: (line) => onLine(line, file.label),
52→    });
53→  }
54→
55→  /**
56→   * 檢查檔案是否已在監控中
57→   */
58→  hasFile(path: string): boolean {
59→    return this.watchers.has(path);
60→  }
61→
62→  /**
63→   * 取得監控中的檔案數量
64→   */
65→  get fileCount(): number {
66→    return this.watchers.size;
67→  }
68→
69→  /**
70→   * 停止所有監控
71→   */
72→  stop(): void {
73→    for (const watcher of this.watchers.values()) {
74→      watcher.stop();
75→    }
76→    this.watchers.clear();
77→  }
78→}
