        continue
    for session in os.listdir(transcripts_dir):
        for root, dirs, files in os.walk(os.path.join(transcripts_dir, session)):
            for fname in files:
                if not fname.endswith('.jsonl'):
                    continue
                path = os.path.join(root, fname)
                try:
                    with open(path) as f:
                        for line in f:
                            d = json.loads(line.strip())
                            role = d.get('role')
                            # Check for non-standard keys at top level
                            top_keys = set(d.keys()) - {'role', 'message'}
                            if top_keys:
                                special_structures.append(f'{path}: extra_keys={top_keys}, snippet={json.dumps(d)[:200]}')
                            msg = d.get('message', {})
                            if isinstance(msg, dict):
                                content = msg.get('content', [])
                                if isinstance(content, list):
                                    for item in content:
                                        if isinstance(item, dict):
                                            ct = item.get('type')
                                            if ct and ct != 'text':
                                                content_types.add(ct)
                                                special_structures.append(f'{path}({role}): type={ct}')
                except:
                    pass

print(f'Non-text content types: {content_types}')
print()
print('Special structures (first 10):')
for s in special_structures[:10]:
