 23→class CursorSessionFinder implements SessionFinder {
 24→  private _baseDir: string;
 25→
 26→  constructor() {
 27→    this._baseDir = join(homedir(), '.cursor', 'projects');
 28→  }
 29→
 30→  getBaseDir(): string {
 31→    return this._baseDir;
 32→  }
 33→
 34→  /**
 35→   * 設定 baseDir（用於測試）
 36→   */
 37→  setBaseDir(dir: string): void {
 38→    this._baseDir = dir;
 39→  }
 40→
 41→  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
 42→    const glob = new Glob('*/agent-transcripts/*/*.jsonl');
 43→    let latest: { path: string; mtime: Date } | null = null;
 44→
 45→    // Cache .workspace-trusted lookups per workspace slug
 46→    const workspacePathCache = new Map<string, string | null>();
 47→
 48→    for await (const file of glob.scan({
 49→      cwd: this._baseDir,
 50→      absolute: true,
 51→    })) {
 52→      // 排除 subagent 檔案
 53→      if (file.includes('/subagents/')) continue;
 54→
 55→      // Project filter
 56→      if (options.project) {
 57→        const matched = await this._matchProject(
 58→          file,
 59→          options.project,
 60→          workspacePathCache
 61→        );
 62→        if (!matched) continue;
 63→      }
 64→
 65→      try {
 66→        const stats = await stat(file);
 67→        if (!latest || stats.mtime > latest.mtime) {
 68→          latest = { path: file, mtime: stats.mtime };
 69→        }
 70→      } catch {
 71→        // 忽略無法讀取的檔案
 72→      }
 73→    }
 74→
 75→    if (!latest) return null;
 76→
 77→    return {
 78→      path: latest.path,
 79→      mtime: latest.mtime,
 80→      agentType: 'cursor',
 81→    };
 82→  }
 83→
 84→  /**
 85→   * 依 session ID 查找 session 檔案
 86→   * Cursor session ID 為 UUID v4
 87→   * 支援部分匹配：精確 > 前綴 > 包含
 88→   */
 89→  async findBySessionId(
 90→    sessionId: string,
 91→    options: { project?: string }
 92→  ): Promise<SessionFile | null> {
 93→    const glob = new Glob('*/agent-transcripts/*/*.jsonl');
 94→    const candidates: { path: string; mtime: Date; priority: number }[] = [];
 95→    const searchTerm = sessionId.toLowerCase();
 96→
 97→    const workspacePathCache = new Map<string, string | null>();
 98→
 99→    for await (const file of glob.scan({
100→      cwd: this._baseDir,
101→      absolute: true,
102→    })) {
103→      if (file.includes('/subagents/')) continue;
104→
105→      if (options.project) {
106→        const matched = await this._matchProject(
107→          file,
108→          options.project,
109→          workspacePathCache
110→        );
111→        if (!matched) continue;
112→      }
113→
114→      // 從路徑提取 UUID（目錄名即為 session ID）
115→      const sessionDir = basename(dirname(file));
116→      const normalizedId = sessionDir.toLowerCase();
117→
118→      let priority = 0;
119→      if (normalizedId === searchTerm) {
120→        // UUID 唯一，精確匹配直接返回
121→        try {
122→          const stats = await stat(file);
123→          return { path: file, mtime: stats.mtime, agentType: 'cursor' };
124→        } catch {
125→          continue;
126→        }
127→      } else if (normalizedId.startsWith(searchTerm)) {
128→        priority = 2; // 前綴匹配
129→      } else if (normalizedId.includes(searchTerm)) {
130→        priority = 1; // 包含匹配
131→      }
132→
133→      if (priority === 0) continue;
134→
135→      try {
136→        const stats = await stat(file);
137→        candidates.push({ path: file, mtime: stats.mtime, priority });
138→      } catch {
139→        // 忽略無法讀取的檔案
140→      }
141→    }
142→
143→    if (candidates.length === 0) return null;
144→
145→    candidates.sort((a, b) => {
146→      if (b.priority !== a.priority) return b.priority - a.priority;
147→      return b.mtime.getTime() - a.mtime.getTime();
148→    });
149→
150→    const best = candidates[0];
151→    if (!best) return null;
152→
153→    return {
154→      path: best.path,
155→      mtime: best.mtime,
156→      agentType: 'cursor',
157→    };
158→  }
159→
160→  /**
161→   * 從 session 檔案取得專案資訊（用於 auto-switch）
162→   * 提取 workspace 目錄作為 projectDir
163→   */
164→  async getProjectInfo(sessionPath: string): Promise<ProjectInfo | null> {
165→    const workspaceDir = this._extractWorkspaceDir(sessionPath);
166→    if (!workspaceDir) return null;
167→
168→    const slug = basename(workspaceDir);
169→    const workspacePath = await this._readWorkspacePath(workspaceDir);
170→    const displayName = workspacePath ? basename(workspacePath) : slug;
171→
172→    return {
173→      projectDir: workspaceDir,
174→      displayName,
175→    };
176→  }
177→
178→  /**
179→   * 在指定專案範圍內找最新的 session（用於 auto-switch）
180→   * @param projectDir - workspace 目錄路徑
181→   */
182→  async findLatestInProject(projectDir: string): Promise<SessionFile | null> {
183→    const transcriptsDir = join(projectDir, 'agent-transcripts');
184→    // glob */*.jsonl 只匹配一層深度，不會匹配 subagents/ 下的檔案
185→    const glob = new Glob('*/*.jsonl');
186→    let latest: { path: string; mtime: Date } | null = null;
187→
188→    for await (const file of glob.scan({
189→      cwd: transcriptsDir,
190→      absolute: true,
191→    })) {
192→      try {
193→        const stats = await stat(file);
194→        if (!latest || stats.mtime > latest.mtime) {
195→          latest = { path: file, mtime: stats.mtime };
196→        }
197→      } catch {
198→        // 忽略
199→      }
200→    }
201→
202→    if (!latest) return null;
203→
204→    return {
205→      path: latest.path,
206→      mtime: latest.mtime,
207→      agentType: 'cursor',
208→    };
209→  }
210→
211→  /**
212→   * 從 session 路徑提取 workspace 目錄
213→   * 路徑格式: ~/.cursor/projects/{slug}/agent-transcripts/{UUID}/{UUID}.jsonl
214→   * 回傳: ~/.cursor/projects/{slug}
215→   */
216→  private _extractWorkspaceDir(sessionPath: string): string | null {
217→    const agentTranscriptsIdx = sessionPath.indexOf('/agent-transcripts/');
218→    if (agentTranscriptsIdx === -1) return null;
219→    return sessionPath.slice(0, agentTranscriptsIdx);
220→  }
221→
222→  /**
223→   * 讀取 .workspace-trusted 檔案中的 workspacePath
224→   */
225→  private async _readWorkspacePath(
226→    workspaceDir: string
227→  ): Promise<string | null> {
228→    try {
229→      const content = await readFile(
230→        join(workspaceDir, '.workspace-trusted'),
231→        'utf-8'
232→      );
233→      const data = JSON.parse(content);
234→      return data.workspacePath || null;
235→    } catch {
236→      return null;
237→    }
238→  }
239→
240→  /**
241→   * 專案模糊匹配
242→   * 匹配 workspace slug 或 .workspace-trusted 的 workspacePath
243→   */
244→  private async _matchProject(
245→    filePath: string,
246→    project: string,
247→    cache: Map<string, string | null>
248→  ): Promise<boolean> {
249→    const pattern = project.toLowerCase();
250→
251→    // 對完整路徑做模糊比對（包含 slug）
252→    if (filePath.toLowerCase().includes(pattern)) return true;
253→
254→    // 嘗試 .workspace-trusted 的 workspacePath
255→    const workspaceDir = this._extractWorkspaceDir(filePath);
256→    if (!workspaceDir) return false;
257→
258→    const slug = basename(workspaceDir);
259→    if (!cache.has(slug)) {
260→      cache.set(slug, await this._readWorkspacePath(workspaceDir));
261→    }
262→
263→    const workspacePath = cache.get(slug);
264→    if (workspacePath && workspacePath.toLowerCase().includes(pattern)) {
265→      return true;
266→    }
267→
268→    return false;
269→  }
270→}
