272→/**
273→ * 從文字中去除 <user_query> 包裝標籤
274→ */
275→function stripUserQueryTags(text: string): string {
276→  return text
277→    .replace(/^<user_query>\s*/s, '')
278→    .replace(/\s*<\/user_query>\s*$/s, '')
279→    .trim();
280→}
281→
282→/**
283→ * 從文字中去除 <attached_files> 區塊
284→ */
285→function stripAttachedFilesTags(text: string): string {
286→  return text.replace(/<attached_files>[\s\S]*?<\/attached_files>/g, '').trim();
287→}
