  1→import { join } from 'node:path';
  2→import { Glob } from 'bun';
  3→import {
  4→  isValidCodexAgentId,
  5→  type CodexSubagentDetector,
  6→} from './subagent-detector.ts';
  7→import { MAIN_LABEL } from '../core/detector-interfaces.ts';
  8→import type { SessionFile, ParsedLine } from '../core/types.ts';
  9→import type { LineParser } from '../agents/agent.interface.ts';
 10→
 11→// ============================================================
 12→// Path Utilities
 13→// ============================================================
 14→
 15→const CODEX_UUID_IN_PATH =
 16→  /([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})\.jsonl$/i;
 17→
 18→/** 從 rollout-*.jsonl 路徑中提取 UUID */
 19→export function extractUUIDFromPath(filePath: string): string {
 20→  return filePath.match(CODEX_UUID_IN_PATH)?.[1] ?? '';
 21→}
 22→
 23→// ============================================================
 24→// Session Scanning
 25→// ============================================================
 26→
 27→/**
 28→ * 掃描主 session JSONL，提取所有 subagent UUID
 29→ */
 30→export async function extractCodexSubagentIds(
 31→  sessionPath: string
 32→): Promise<string[]> {
 33→  let text: string;
 34→  try {
 35→    const file = Bun.file(sessionPath);
 36→    if (!(await file.exists())) return [];
 37→    text = await file.text();
 38→  } catch {
 39→    return [];
 40→  }
 41→
 42→  const seen = new Set<string>();
 43→  for (const line of text.split('\n')) {
 44→    if (!line.trim()) continue;
 45→    try {
 46→      const data = JSON.parse(line);
 47→      if (
 48→        data.type === 'response_item' &&
 49→        data.payload?.type === 'function_call_output'
 50→      ) {
 51→        const output = JSON.parse(data.payload.output ?? '{}');
 52→        const agentId = output.agent_id;
 53→        if (agentId && isValidCodexAgentId(agentId)) {
 54→          seen.add(agentId);
 55→        }
 56→      }
 57→    } catch {
 58→      // ignore malformed lines
 59→    }
 60→  }
 61→
 62→  return Array.from(seen);
 63→}
 64→
 65→/**
 66→ * 根據 agentIds 在 dateDir 中找到對應的 JSONL 檔案
 67→ * 使用單一 Glob 掃描 + 平行 stat，效率為 O(M+N)
 68→ */
 69→export async function buildCodexSubagentFiles(
 70→  dateDir: string,
 71→  agentIds: string[]
 72→): Promise<SessionFile[]> {
 73→  if (agentIds.length === 0) return [];
 74→
 75→  const idSet = new Set(agentIds);
 76→  const glob = new Glob('rollout-*.jsonl');
 77→  const statPromises: Promise<SessionFile | null>[] = [];
 78→
 79→  for await (const file of glob.scan(dateDir)) {
 80→    const uuid = extractUUIDFromPath(file);
 81→    if (uuid && idSet.has(uuid)) {
 82→      const fullPath = join(dateDir, file);
 83→      statPromises.push(
 84→        Bun.file(fullPath)
 85→          .stat()
 86→          .then(
 87→            (stat): SessionFile => ({
 88→              path: fullPath,
 89→              mtime: stat.mtime ?? new Date(0),
 90→              agentType: 'codex',
 91→            })
 92→          )
 93→          .catch(() => null)
 94→      );
 95→    }
 96→  }
 97→
 98→  const results = await Promise.all(statPromises);
 99→  return results.filter((r): r is SessionFile => r !== null);
100→}
101→
102→// ============================================================
103→// Line Handler
104→// ============================================================
105→
106→/**
107→ * 建立 Codex 主 session 的行處理器，解析 spawn/output/done 事件
108→ */
109→export function createCodexOnLineHandler(
110→  detector: CodexSubagentDetector
111→): (line: string, label: string) => void {
112→  return (line: string, label: string) => {
113→    if (label !== MAIN_LABEL) return;
114→
115→    if (line.includes('"spawn_agent"')) {
116→      try {
117→        const data = JSON.parse(line);
118→        if (
119→          data.type === 'response_item' &&
120→          data.payload?.type === 'function_call' &&
121→          data.payload?.name === 'spawn_agent'
122→        ) {
123→          const args = JSON.parse(data.payload.arguments ?? '{}');
124→          detector.handleSpawnAgent(
125→            data.payload.call_id,
126→            args.agent_type ?? '',
127→            args.message ?? ''
128→          );
129→        }
130→      } catch {
131→        /* ignore */
132→      }
133→    }
134→
135→    if (line.includes('"function_call_output"')) {
136→      try {
137→        const data = JSON.parse(line);
138→        if (
139→          data.type === 'response_item' &&
140→          data.payload?.type === 'function_call_output'
141→        ) {
142→          const output = JSON.parse(data.payload.output ?? '{}');
143→          if (output.agent_id) {
144→            detector.handleSpawnAgentOutput(data.payload.call_id, {
145→              agent_id: output.agent_id,
146→              nickname: output.nickname,
147→            });
148→          }
149→        }
150→      } catch {
151→        /* ignore */
152→      }
153→    }
154→
155→    if (line.includes('"resume_agent"') || line.includes('"send_input"')) {
156→      try {
157→        const data = JSON.parse(line);
158→        if (
159→          data.type === 'response_item' &&
160→          data.payload?.type === 'function_call' &&
161→          (data.payload?.name === 'resume_agent' ||
162→            data.payload?.name === 'send_input')
163→        ) {
164→          const args = JSON.parse(data.payload.arguments ?? '{}');
165→          if (args.agent_id) {
166→            detector.handleSubagentResume(args.agent_id);
167→          }
168→        }
169→      } catch {
170→        /* ignore */
171→      }
172→    }
173→
174→    if (line.includes('<subagent_notification>')) {
175→      try {
176→        const data = JSON.parse(line);
177→        const text = data.payload?.content?.[0]?.text ?? '';
178→        const match = text.match(
179→          /<subagent_notification>(.*?)<\/subagent_notification>/s
180→        );
181→        if (match) {
182→          const notif = JSON.parse(match[1]);
183→          if (notif.agent_id && notif.status?.completed !== undefined) {
184→            detector.handleSubagentDone(notif.agent_id);
185→          }
186→        }
187→      } catch {
188→        /* ignore */
189→      }
190→    }
191→  };
192→}
193→
194→// ============================================================
195→// Last Assistant Message Reader
196→// ============================================================
197→
198→/**
199→ * 讀取 Codex subagent JSONL 最後一條 assistant 訊息
200→ * 用於 pane 關閉前輸出最後結果
201→ * @param parser - 由呼叫方注入，避免循環依賴（watch-builder.ts → codex-agent.ts）
202→ */
203→export async function readLastCodexAssistantMessage(
204→  filePath: string,
205→  parser: LineParser
206→): Promise<ParsedLine[]> {
207→  try {
208→    const file = Bun.file(filePath);
209→    if (!(await file.exists())) return [];
210→    const text = await file.text();
211→    const lines = text.split('\n').filter((l) => l.trim());
212→
213→    for (let i = lines.length - 1; i >= 0; i--) {
214→      try {
215→        const data = JSON.parse(lines[i]!);
216→        if (
217→          data.type === 'response_item' &&
218→          data.payload?.type === 'message' &&
219→          data.payload?.role === 'assistant'
220→        ) {
221→          const content = data.payload.content as
222→            | Array<{ type: string; text?: string }>
223→            | undefined;
224→          const msgText = content?.find(
225→            (c) => c.type === 'output_text' || c.type === 'input_text'
226→          )?.text;
227→          if (!msgText?.trim()) continue;
228→
229→          const parsed = parser.parse(lines[i]!);
230→          if (parsed) return [parsed];
231→        }
232→      } catch {
233→        /* ignore */
234→      }
235→    }
236→  } catch {
237→    /* ignore */
238→  }
239→  return [];
240→}
