627→/**
628→ * Interactive 模式共用：建立 SessionManager（Claude/Codex 兩種 interactive 模式都相同）
629→ */
630→function createInteractiveSessionManager(
631→  displayController: DisplayController
632→): SessionManager {
633→  const manager = new SessionManager({
634→    bufferSize: 1000,
635→    onOutput: (content: string, _session: WatcherSession) => {
636→      displayController.write(content);
637→    },
638→    onSessionAdded: (session: WatcherSession) => {
639→      displayController.write(
640→        chalk.yellow(`New session added: ${session.label}`)
641→      );
642→      displayController.updateStatusLine(
643→        manager.getAllSessions(),
644→        manager.getActiveIndex()
645→      );
646→    },
647→    onSessionSwitched: (
648→      session: WatcherSession,
649→      allSessions: WatcherSession[]
650→    ) => {
651→      const historyContent = session.buffer.slice();
652→      displayController.updateStatusLine(allSessions, manager.getActiveIndex());
653→      displayController.showSwitchMessage(session, historyContent);
654→    },
655→  });
656→  return manager;
657→}
