662→async function startClaudeInteractiveWatch(
663→  sessionFile: SessionFile,
664→  formatter: Formatter,
665→  options: CliOptions,
666→  initialSubagent: SessionFile | null = null
667→): Promise<void> {
668→  // TTY 檢查：非 TTY 環境自動降級到普通多檔案監控模式
669→  if (!process.stdin.isTTY) {
670→    console.warn(
671→      chalk.yellow(
672→        'Warning: Interactive mode not available in non-TTY environment.\n' +
673→          'Switching to standard multi-watch mode.\n' +
674→          'Keyboard controls (Tab to switch) will not be available.'
675→      )
676→    );
677→    await startClaudeMultiWatch(
678→      sessionFile,
679→      formatter,
680→      options,
681→      initialSubagent
682→    );
683→    return;
684→  }
685→
686→  const lockedProjectDir = dirname(sessionFile.path);
687→
688→  // 建立 DisplayController
689→  const displayController = new DisplayController({
690→    persistentStatusLine: true,
691→    historyLines: 50,
692→  });
693→
694→  let sessionManager!: SessionManager;
695→  let parsers = new Map<string, LineParser>();
696→  let multiWatcher: MultiFileWatcher | null = null;
697→  let detector: SubagentDetector | null = null;
698→  let currentSessionFile = sessionFile;
699→
700→  const buildInteractiveState = async (
701→    targetSessionFile: SessionFile,
702→    initialSubagentFile: SessionFile | null,
703→    showIntro: boolean
704→  ): Promise<void> => {
705→    const subagentsDir = getSubagentsDir(targetSessionFile.path);
706→
707→    sessionManager = createInteractiveSessionManager(displayController);
708→    const mainTitle =
709→      targetSessionFile.customTitle ??
710→      (await readCustomTitle(targetSessionFile.path)) ??
711→      undefined;
712→    sessionManager.addSession(
713→      'main',
714→      MAIN_LABEL,
715→      targetSessionFile.path,
716→      mainTitle
717→    );
718→
719→    // 掃描現有的 subagent（優先使用目錄掃描，確保找到所有檔案）
720→    const dirAgentIds = await scanForNewSubagents(subagentsDir, new Set());
721→    const existingAgentIds = new Set(dirAgentIds);
722→
723→    // 如果有從 sessionId 指定的 subagent，確保它被加入
724→    if (initialSubagentFile) {
725→      const initialAgentId = basename(
726→        initialSubagentFile.path,
727→        '.jsonl'
728→      ).replace(/^agent-/, '');
729→      existingAgentIds.add(initialAgentId);
730→    }
731→
732→    const existingSubagentFiles = await buildSubagentFiles(
733→      subagentsDir,
734→      existingAgentIds
735→    );
736→    for (const { agentId, path } of existingSubagentFiles) {
737→      sessionManager.addSession(agentId, makeAgentLabel(agentId), path);
738→    }
739→
740→    if (showIntro) {
741→      if (existingAgentIds.size > 0) {
742→        log(
743→          options.quiet,
744→          chalk.gray(`Found ${existingAgentIds.size} subagent(s)`)
745→        );
746→      }
747→      log(
748→        options.quiet,
749→        chalk.gray('Interactive mode: Press Tab to switch, q to quit')
750→      );
751→      log(options.quiet, chalk.gray('---'));
752→    }
753→
754→    // 為每個來源建立獨立的 parser
755→    parsers = new Map<string, LineParser>();
756→    for (const session of sessionManager.getAllSessions()) {
757→      const parserAgent = new ClaudeAgent({ verbose: options.verbose });
758→      parsers.set(session.label, parserAgent.parser);
759→    }
760→
761→    const watcher = new MultiFileWatcher();
762→    multiWatcher = watcher;
763→
764→    detector = new SubagentDetector(existingAgentIds, {
765→      subagentsDir,
766→      output: new DisplayControllerOutputHandler(displayController),
767→      watcher: { addFile: (f) => watcher.addFile(f) },
768→      session: new InteractiveSessionHandler(sessionManager, displayController),
769→      enabled: true, // Interactive 模式一定是 follow
770→    });
771→    detector.startDirectoryWatch();
772→  };
773→
774→  const startWatcher = async (): Promise<void> => {
775→    if (!multiWatcher || !detector) return;
776→    const activeDetector = detector;
777→
778→    const files = sessionManager.getWatchedFiles();
779→
780→    await multiWatcher.start(files, {
781→      follow: options.follow,
782→      pollInterval: options.sleepInterval,
783→      initialLines: options.lines,
784→      onLine: createOnLineHandler({
785→        parsers,
786→        formatter,
787→        detector: activeDetector,
788→        onOutput: (formatted, label) =>
789→          sessionManager.handleOutput(label, formatted),
790→        verbose: options.verbose,
791→        onTitleUpdate: (title) => {
792→          sessionManager.updateSessionDisplayName('main', title);
793→          displayController.updateStatusLine(
794→            sessionManager.getAllSessions(),
795→            sessionManager.getActiveIndex()
796→          );
797→        },
798→      }),
799→      onError: (error) => {

800→        displayController.write(chalk.red(`Error: ${error.message}`));
801→      },
802→    });
803→  };
804→
805→  // 設定鍵盤監聽
806→  if (process.stdin.isTTY) {
807→    process.stdin.setRawMode(true);
808→    process.stdin.resume();
809→    process.stdin.setEncoding('utf8');
810→
811→    process.stdin.on('data', (key: string) => {
812→      // Ctrl+C
813→      if (key === '\u0003') {
814→        cleanup();
815→        process.exit(0);
816→      }
817→      // q - quit
818→      if (key === 'q' || key === 'Q') {
819→        cleanup();
820→        process.exit(0);
821→      }
822→      // Tab - switch next
823→      if (key === '\t') {
824→        sessionManager.switchNext();
825→      }
826→      // Shift+Tab (varies by terminal, common: \u001b[Z)
827→      if (key === '\u001b[Z') {
828→        sessionManager.switchPrev();
829→      }
830→      // n - switch next (alternative)
831→      if (key === 'n' || key === 'N') {
832→        sessionManager.switchNext();
833→      }
834→      // p - switch prev (alternative)
835→      if (key === 'p' || key === 'P') {
836→        sessionManager.switchPrev();
837→      }
838→    });
839→  }
840→
841→  // 初始化狀態並啟動監控
842→  await buildInteractiveState(currentSessionFile, initialSubagent, true);
843→
844→  // 初始化 DisplayController
845→  displayController.init();
846→
847→  // 顯示初始狀態列
848→  displayController.updateStatusLine(
849→    sessionManager.getAllSessions(),
850→    sessionManager.getActiveIndex()
851→  );
852→
853→  await startWatcher();
854→
855→  const switchToSession = async (
856→    nextSessionFile: SessionFile
857→  ): Promise<void> => {
858→    detector?.stop();
859→    if (multiWatcher) {
860→      multiWatcher.stop();
861→    }
862→
863→    currentSessionFile = nextSessionFile;
864→    await buildInteractiveState(nextSessionFile, null, false);
865→
866→    displayController.updateStatusLine(
867→      sessionManager.getAllSessions(),
868→      sessionManager.getActiveIndex()
869→    );
870→
871→    await startWatcher();
872→
873→    const nextSessionId = basename(nextSessionFile.path, '.jsonl');
874→    const switchTitle = await readCustomTitle(nextSessionFile.path);
875→    const switchTitleSuffix = switchTitle ? ` "${switchTitle}"` : '';
876→    displayController.write(
877→      chalk.gray(
878→        `Switched to latest session: ${nextSessionId}${switchTitleSuffix}`
879→      )
880→    );
881→  };
882→
883→  const superFollow = createSuperFollowController({
884→    projectDir: lockedProjectDir,
885→    getCurrentPath: () => currentSessionFile.path,
886→    onSwitch: switchToSession,
887→    autoSwitch: options.autoSwitch,
888→    findLatestInProject: findLatestMainSessionInProject,
889→  });
890→
891→  superFollow.start();
892→
893→  // 清理函式
894→  const cleanup = (): void => {
895→    superFollow.stop();
896→    // 先清理 DisplayController（恢復終端設定）
897→    displayController.destroy();
898→    detector?.stop();
899→    log(options.quiet, chalk.gray('\nStopping...'));
900→    if (process.stdin.isTTY) {
901→      process.stdin.setRawMode(false);
902→    }
903→    if (multiWatcher) {
904→      multiWatcher.stop();
905→    }
906→  };
907→
908→  // 處理中斷信號
909→  process.on('SIGINT', () => {
910→    cleanup();
911→    process.exit(0);
912→  });
913→
914→  // 保持程式運行（interactive 模式必須是 follow）
915→  displayController.write(
916→    chalk.gray('Watching for changes... (Tab to switch, q to quit)')
917→  );
918→}
