1158→/**
1159→ * Codex 多檔案監控（主 session + subagents）
1160→ */
1161→async function startCodexMultiWatch(
1162→  sessionFile: SessionFile,
1163→  formatter: Formatter,
1164→  options: CliOptions
1165→): Promise<void> {
1166→  // 1. dateDir（Codex subagent 與主 session 在同一個日期目錄）
1167→  const dateDir = dirname(sessionFile.path);
1168→
1169→  // 2. projectDir（super-follow 用），從 session_meta 取得 cwd
1170→  const codexAgent = new CodexAgent({ verbose: options.verbose });
1171→  const projectInfo = codexAgent.finder.getProjectInfo
1172→    ? await codexAgent.finder.getProjectInfo(sessionFile.path)
1173→    : null;
1174→  const projectDir = projectInfo?.projectDir ?? dateDir;
1175→
1176→  // 3. 掃描既有 subagent IDs
1177→  const existingIds = options.withSubagents
1178→    ? await extractCodexSubagentIds(sessionFile.path)
1179→    : [];
1180→
1181→  // 4. 建立監控檔案列表
1182→  const existingSubFiles =
1183→    options.withSubagents && existingIds.length > 0
1184→      ? await buildCodexSubagentFiles(dateDir, existingIds)
1185→      : [];
1186→
1187→  const files: WatchedFile[] = [
1188→    { path: sessionFile.path, label: MAIN_LABEL },
1189→    ...existingSubFiles.map((f) => {
1190→      // makeCodexAgentLabel 接受 UUID，不是路徑
1191→      const agentId = extractUUIDFromPath(f.path);
1192→      return { path: f.path, label: makeCodexAgentLabel(agentId) };
1193→    }),
1194→  ];
1195→
1196→  if (existingIds.length > 0) {
1197→    log(options.quiet, chalk.gray(`Found ${existingIds.length} subagent(s)`));
1198→  }
1199→  log(options.quiet, chalk.gray('---'));

1200→
1201→  // 5. Codex parser 無狀態，多 file 共用一個實例
1202→  const parser = codexAgent.parser;
1203→
1204→  // 6. PaneManager 初始化（Phase 2: --pane 支援）
1205→  let paneManager: PaneManager | null = null;
1206→  if (options.pane) {
1207→    const controller = createTerminalController();
1208→    if (controller.isAvailable()) {
1209→      paneManager = new PaneManager(
1210→        controller,
1211→        (agentId, _subagentPath) => {
1212→          const runtime = `"${process.argv[0]}"`;
1213→          const script = `"${process.argv[1]}"`;
1214→          return `${runtime} ${script} codex --subagent ${agentId} -q --no-pane`;
1215→        },
1216→        (msg) => log(options.quiet, chalk.gray(msg))
1217→      );
1218→    } else {
1219→      log(
1220→        options.quiet,
1221→        chalk.yellow('Warning: tmux not detected, --pane disabled')
1222→      );
1223→    }
1224→  }
1225→
1226→  const pm = paneManager;
1227→
1228→  // Codex label 用短 ID（如 019cc375-8a57），但 PaneManager 用完整 UUID 作 key
1229→  // 此映射讓 shouldOutput 能從短 ID 反查完整 UUID
1230→  const shortIdToFullId = new Map<string, string>();
1231→  function registerShortId(agentId: string): void {
1232→    const parts = agentId.split('-');
1233→    const shortId = `${parts[0]}-${(parts[4] ?? '').slice(0, 4)}`;
1234→    shortIdToFullId.set(shortId, agentId);
1235→  }
1236→
1237→  // pane 模式下：既有 subagent 加入 suppress set（完整 UUID v7），避免歷史內容污染 main pane
1238→  const suppressedForPane = new Set<string>();
1239→
1240→  /** 預填既有 subagent 路徑到 detector，同步短 ID 映射，並填充 suppressedForPane（若有 pane） */
1241→  function prefillExistingSubagents(
1242→    det: CodexSubagentDetector,
1243→    files: SessionFile[]
1244→  ): void {
1245→    for (const f of files) {
1246→      const uuid = extractUUIDFromPath(f.path);
1247→      if (pm) {
1248→        registerShortId(uuid);
1249→        suppressedForPane.add(uuid);
1250→      }
1251→      det.registerExistingAgent(uuid, f.path);
1252→    }
1253→  }
1254→  const shouldOutput = pm
1255→    ? (label: string) => {
1256→        if (label === MAIN_LABEL) return true;
1257→        const shortId = extractAgentIdFromLabel(label);
1258→        const fullId = shortIdToFullId.get(shortId) ?? shortId;
1259→        if (suppressedForPane.has(fullId)) return false;
1260→        return !pm.hasPaneForAgent(fullId);
1261→      }
1262→    : undefined;
1263→
1264→  const openPaneForSubagent = pm
1265→    ? (agentId: string, subagentPath: string, description?: string) => {
1266→        registerShortId(agentId);
1267→        pm.openPane(agentId, subagentPath, description).catch(
1268→          (err: unknown) => {
1269→            log(
1270→              options.quiet,
1271→              chalk.yellow(`[pane] Failed to open pane: ${err}`)
1272→            );
1273→          }
1274→        );
1275→      }
1276→    : undefined;
1277→
1278→  const onSubagentDone = pm
1279→    ? (agentId: string) => {
1280→        // 使用 detector.getAgentPath() 取路徑（detector 是 let 變數，切換 session 後自動指向新 detector）
1281→        const subPath = detector.getAgentPath(agentId);
1282→
1283→        (async () => {
1284→          try {
1285→            if (subPath) {
1286→              const parts = await readLastCodexAssistantMessage(
1287→                subPath,
1288→                parser
1289→              );
1290→              const label = makeCodexAgentLabel(agentId);
1291→              for (const part of parts) {
1292→                part.sourceLabel = label;
1293→                console.log(formatter.format(part));
1294→              }
1295→            }
1296→          } finally {
1297→            await pm.closePaneByAgentId(agentId);
1298→          }
1299→        })().catch(() => {});
1300→      }
1301→    : undefined;
1302→
1303→  // 7. MultiFileWatcher + CodexSubagentDetector
1304→  let multiWatcher = new MultiFileWatcher();
1305→
1306→  let detector = new CodexSubagentDetector(existingIds, {
1307→    sessionDateDir: dateDir,
1308→    output: new ConsoleOutputHandler(),
1309→    watcher: { addFile: (f) => multiWatcher.addFile(f) },
1310→    enabled: options.follow && options.withSubagents,
1311→    onNewSubagent: openPaneForSubagent,
1312→    onSubagentEnter: openPaneForSubagent,
1313→    onSubagentDone,
1314→  });
1315→
1316→  // 預填既有 subagent 路徑，讓 resume_agent 事件能找到路徑（用於 --pane onSubagentEnter）
1317→  // 同時填充 suppressedForPane（由 prefillExistingSubagents 內部處理）
1318→  prefillExistingSubagents(detector, existingSubFiles);
1319→
1320→  // 8. 組合 line handler：detection + output
1321→  // makeOnLine() 使用 closure，switchToSession 更新 detectionHandler 後自動生效
1322→  let detectionHandler = createCodexOnLineHandler(detector);
1323→  const makeOnLine = () => (line: string, label: string) => {
1324→    detectionHandler(line, label); // 只對 MAIN label 做 detection（內部已過濾）
1325→    if (shouldOutput && !shouldOutput(label)) return;
1326→    const parsed = parser.parse(line);
1327→    if (!parsed) return;
1328→    parsed.sourceLabel = label;
1329→    console.log(formatter.format(parsed));
1330→  };
1331→
1332→  // 9. Super-follow：包含完整的 switchToSession 重建邏輯
1333→  let currentSessionPath = sessionFile.path;
1334→
1335→  const switchToSession = async (nextFile: SessionFile): Promise<void> => {
1336→    paneManager?.closeAll(); // 關閉現有 pane
1337→    shortIdToFullId.clear();
1338→    if (pm) suppressedForPane.clear(); // 與 prefillExistingSubagents 配對清空
1339→    detector.stop();
1340→    multiWatcher.stop();
1341→
1342→    currentSessionPath = nextFile.path;
1343→    const newDateDir = dirname(nextFile.path);
1344→
1345→    const newExistingIds = options.withSubagents
1346→      ? await extractCodexSubagentIds(nextFile.path)
1347→      : [];
1348→    const newSubFiles =
1349→      options.withSubagents && newExistingIds.length > 0
1350→        ? await buildCodexSubagentFiles(newDateDir, newExistingIds)
1351→        : [];
1352→
1353→    const newFiles: WatchedFile[] = [
1354→      { path: nextFile.path, label: MAIN_LABEL },
1355→      ...newSubFiles.map((f) => {
1356→        const agentId = extractUUIDFromPath(f.path);
1357→        return { path: f.path, label: makeCodexAgentLabel(agentId) };
1358→      }),
1359→    ];
1360→
1361→    log(
1362→      options.quiet,
1363→      chalk.gray(
1364→        `--- Switched to session ${basename(nextFile.path, '.jsonl')} ---`
1365→      )
1366→    );
1367→
1368→    const newMultiWatcher = new MultiFileWatcher();
1369→    const newDetector = new CodexSubagentDetector(newExistingIds, {
1370→      sessionDateDir: newDateDir,
1371→      output: new ConsoleOutputHandler(),
1372→      watcher: { addFile: (f) => newMultiWatcher.addFile(f) },
1373→      enabled: options.follow && options.withSubagents,
1374→      onNewSubagent: openPaneForSubagent,
1375→      onSubagentEnter: openPaneForSubagent,
1376→      onSubagentDone,
1377→    });
1378→
1379→    // 預填既有 subagent 路徑 + 短 ID 映射
1380→    prefillExistingSubagents(newDetector, newSubFiles);
1381→
1382→    multiWatcher = newMultiWatcher;
1383→    detector = newDetector;
1384→    detectionHandler = createCodexOnLineHandler(newDetector);
1385→
1386→    await multiWatcher.start(newFiles, {
1387→      follow: options.follow,
1388→      pollInterval: options.sleepInterval,
1389→      initialLines: options.lines,
1390→      onLine: makeOnLine(),
1391→      onError: (error) => console.error(chalk.red(`Error: ${error.message}`)),
1392→    });
1393→  };
1394→
1395→  const superFollow = createSuperFollowController({
1396→    projectDir,
1397→    getCurrentPath: () => currentSessionPath,
1398→    onSwitch: switchToSession,
1399→    autoSwitch: options.autoSwitch,

1400→    findLatestInProject: (cwd) => codexAgent.finder.findLatestInProject!(cwd),
1401→  });
1402→
1403→  // 10. 信號處理
1404→  process.on('SIGINT', () => {
1405→    superFollow.stop();
1406→    detector.stop();
1407→    multiWatcher.stop();
1408→    paneManager?.closeAll();
1409→    console.log(chalk.gray('\nStopping...'));
1410→    process.exit(0);
1411→  });
1412→
1413→  // 11. 啟動監控
1414→  await multiWatcher.start(files, {
1415→    follow: options.follow,
1416→    pollInterval: options.sleepInterval,
1417→    initialLines: options.lines,
1418→    onLine: makeOnLine(),
1419→    onError: (error) => console.error(chalk.red(`Error: ${error.message}`)),
1420→  });
1421→
1422→  if (!options.follow) process.exit(0);
1423→  superFollow.start();
1424→  log(options.quiet, chalk.gray('Watching for changes... (Ctrl+C to stop)'));
1425→}
