1427→/**
1428→ * 單檔案監控（Codex/Gemini）
1429→ */
1430→async function startSingleWatch(
1431→  agent: Agent,
1432→  sessionFile: SessionFile,
1433→  formatter: Formatter,
1434→  options: CliOptions
1435→): Promise<void> {
1436→  log(options.quiet, chalk.gray('---'));
1437→
1438→  // 取得專案資訊（用於 auto-switch）
1439→  const projectInfo =
1440→    options.autoSwitch && agent.finder.getProjectInfo
1441→      ? await agent.finder.getProjectInfo(sessionFile.path)
1442→      : null;
1443→
1444→  let currentPath = sessionFile.path;
1445→  let watcher = new FileWatcher();
1446→
1447→  // 為 Gemini 準備可重建的 parser（避免狀態殘留）
1448→  // Codex parser 是無狀態的，不需要重建
1449→  let currentParser = agent.parser;
1450→
1451→  // 建立 onLine handler 函數（單一 agent 用，與 Claude 多檔案的 createOnLineHandler 不同）
1452→  const makeSingleLineHandler =
1453→    (parser: LineParser) =>
1454→    (line: string): void => {
1455→      if (options.agentType === 'gemini') {
1456→        // Gemini 模式：parser 有狀態追蹤，每次只回傳一個部分
1457→        // 需要反覆呼叫直到沒有更多內容
1458→        let parsed = parser.parse(line);
1459→        while (parsed) {
1460→          console.log(formatter.format(parsed));
1461→          parsed = parser.parse(line);
1462→        }
1463→      } else {
1464→        // Codex JSONL 模式：每行一個事件，單次處理
1465→        const parsed = parser.parse(line);
1466→        if (parsed) {
1467→          console.log(formatter.format(parsed));
1468→        }
1469→      }
1470→    };
1471→
1472→  // 切換到新 session 的函數
1473→  const switchToSession = async (nextFile: SessionFile): Promise<void> => {
1474→    watcher.stop();
1475→    currentPath = nextFile.path;
1476→
1477→    log(
1478→      options.quiet,
1479→      chalk.gray(`--- Switched to ${basename(nextFile.path)} ---`)
1480→    );
1481→
1482→    // Gemini 需要重建 parser 以清除狀態（processedMessageIds 等）
1483→    if (options.agentType === 'gemini') {
1484→      const newAgent = new GeminiAgent({ verbose: options.verbose });
1485→      currentParser = newAgent.parser;
1486→    }
1487→
1488→    watcher = new FileWatcher();
1489→    await watcher.start(nextFile.path, {
1490→      follow: true,
1491→      pollInterval: options.sleepInterval,
1492→      initialLines: options.lines,
1493→      jsonMode: options.agentType === 'gemini',
1494→      onLine: makeSingleLineHandler(currentParser),
1495→      onError: (error) => {
1496→        console.error(chalk.red(`Error: ${error.message}`));
1497→      },
1498→    });
1499→  };

