  return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(id);
}

// Scan subagentsDir for new subagent files not in knownAgentIds
// Returns array of new agentIds. Uses UUID regex on filename (*.jsonl)
export async function scanCursorSubagents(
  subagentsDir: string,
  knownAgentIds: Set<string>
): Promise<string[]>

// Build file list with stat info for existing subagent IDs
// Parallel stat calls, sorted by birthtime (oldest first)
export async function buildCursorSubagentFiles(
  subagentsDir: string,
  agentIds: string[]
): Promise<SessionFile[]>

// Make short label from UUID (first 8 chars)
export function makeCursorAgentLabel(agentId: string): string {
  return makeAgentLabel(agentId.slice(0, 8));
}
```

### Step 2: Create CursorSubagentDetector

**File**: `src/cursor/subagent-detector.ts` (new file)

Purely directory-watch based detector. Simplified from Claude's SubagentDetector.

```typescript
export class CursorSubagentDetector {
  private knownAgentIds = new Set<string>();
  private dirWatcher: FSWatcher | null = null;
  private parentWatcher: FSWatcher | null = null;  // fallback for missing subagents/ dir
  private stopped = false;
  private scanTimer: ReturnType<typeof setTimeout> | null = null;

  constructor(
    private subagentsDir: string,
    private config: {
      output: OutputHandler;
      watcher: WatcherHandler;
      session?: SessionHandler;
      enabled: boolean;
      onNewSubagent?: (agentId: string, path: string) => void;
      onSubagentDone?: (agentId: string) => void;
      hasPane?: (agentId: string) => boolean;
    }
  ) {}

  registerExistingAgent(agentId: string, path: string): void
  startDirectoryWatch(): void  // fs.watch on subagentsDir with parent fallback
  stop(): void
  private scheduleScan(): void
  private async scanAndRegister(): Promise<void>
  private tryWatchSubagentsDir(): boolean
  private watchParentForSubagentsDir(): void  // watches dirname(subagentsDir) for creation
}
```

