 10→// ============================================================
 11→// UUID Validation
 12→// ============================================================
 13→
 14→const UUID_REGEX =
 15→  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
 16→
 17→export function isValidCodexAgentId(id: string): boolean {
 18→  return UUID_REGEX.test(id);
 19→}
 20→
 21→/**
 22→ * 取 UUID 的高位時間戳段 + node 段前 4 碼作為短 label
 23→ * 例如 '019cc375-8a57'（避免 UUID v7 前兩段均為 timestamp 導致碰撞）
 24→ */
 25→export function makeCodexAgentLabel(agentId: string): string {
 26→  const parts = agentId.split('-');
 27→  // parts[4] 為 node/random 段，提供唯一性；parts[0] 為可讀時間戳
 28→  const shortId = `${parts[0]}-${(parts[4] ?? '').slice(0, 4)}`;
 29→  return makeAgentLabel(shortId);
 30→}
 31→
 32→// ============================================================
 33→// Config & Types
 34→// ============================================================
 35→
 36→export interface CodexSubagentDetectorConfig {
 37→  /** dirname(mainSessionPath) — 日期目錄 */
 38→  sessionDateDir: string;
 39→  output: OutputHandler;
 40→  watcher: WatcherHandler;
 41→  /** options.follow && options.withSubagents */
 42→  enabled: boolean;
 43→  onNewSubagent?: (agentId: string, path: string, description?: string) => void;
 44→  /** 觸發條件：resume_agent / send_input 且 agentId 已知 */
 45→  onSubagentEnter?: (agentId: string, path: string) => void;
 46→  onSubagentDone?: (agentId: string) => void;
 47→}
 48→
 49→interface PendingSpawn {
 50→  agentType: string;
 51→  message: string;
 52→  timer: ReturnType<typeof setTimeout>;
 53→}
 54→
 55→// ============================================================
 56→// File finder with retry
 57→// ============================================================
 58→
 59→const SUBAGENT_FILE_RETRY: RetryConfig = {
 60→  maxRetries: 30,
 61→  retryDelay: 300,
 62→  initialDelay: 0,
 63→};
 64→
 65→async function findSubagentFile(
 66→  dateDir: string,
 67→  agentId: string,
 68→  retry: RetryConfig = SUBAGENT_FILE_RETRY
 69→): Promise<string | null> {
 70→  const glob = new Glob(`rollout-*-${agentId}.jsonl`);
 71→  for (let i = 0; i < retry.maxRetries; i++) {
 72→    for await (const file of glob.scan(dateDir)) {
 73→      return join(dateDir, file);
 74→    }
 75→    if (i < retry.maxRetries - 1)
 76→      await new Promise((r) => setTimeout(r, retry.retryDelay));
 77→  }
 78→  return null;
 79→}
 80→
 81→// ============================================================
 82→// CodexSubagentDetector
 83→// ============================================================
 84→
 85→export class CodexSubagentDetector {
 86→  private pendingSpawns: Map<string, PendingSpawn> = new Map();
 87→  private registeredAgentPaths: Map<string, string> = new Map();
 88→  private config: CodexSubagentDetectorConfig;
 89→  private stopped = false;
 90→
 91→  constructor(
 92→    _existingAgentIds: string[],
 93→    config: CodexSubagentDetectorConfig
 94→  ) {
 95→    this.config = config;
 96→    // existingAgentIds reserved for future deduplication use
 97→  }
 98→
 99→  /**
100→   * 預先登錄已存在的 subagent（供 handleSubagentResume 查詢）
101→   */
102→  registerExistingAgent(agentId: string, path: string): void {
103→    this.registeredAgentPaths.set(agentId, path);
104→  }
105→
106→  handleSpawnAgent(callId: string, agentType: string, message: string): void {
107→    if (!this.config.enabled) return;
108→
109→    // 防止同一 callId 重複登錄導致舊 timer 洩漏
110→    const existing = this.pendingSpawns.get(callId);
111→    if (existing) clearTimeout(existing.timer);
112→
113→    const timer = setTimeout(() => {
114→      this.pendingSpawns.delete(callId);
115→    }, 60000);
116→
117→    this.pendingSpawns.set(callId, { agentType, message, timer });
118→  }
119→
120→  handleSpawnAgentOutput(
121→    callId: string,
122→    output: { agent_id: string; nickname?: string }
123→  ): void {
124→    if (!this.config.enabled) return;
125→
126→    const pending = this.pendingSpawns.get(callId);
127→    if (!pending) {
128→      this.config.output.debug(`Codex: unknown callId ${callId}, ignoring`);
129→      return;
130→    }
131→
132→    const agentId = output.agent_id;
133→    if (!isValidCodexAgentId(agentId)) {
134→      this.config.output.warn(
135→        `Codex: invalid agent_id format (not UUID): ${agentId}`
136→      );
137→      return;
138→    }
139→
140→    // Skip already-registered agents (pre-filled at startup via registerExistingAgent)
141→    if (this.registeredAgentPaths.has(agentId)) {
142→      clearTimeout(pending.timer);
143→      this.pendingSpawns.delete(callId);
144→      return;
145→    }
146→
147→    // Fire async, but don't await in sync handler
148→    this._resolveSubagent(callId, pending, agentId, output.nickname).catch(
149→      (err) => {
150→        this.config.output.error(
151→          `Codex: Failed to resolve subagent ${agentId} - ${err instanceof Error ? err.message : String(err)}`
152→        );
153→      }
154→    );
155→  }
156→
157→  private async _resolveSubagent(
158→    callId: string,
159→    pending: PendingSpawn,
160→    agentId: string,
161→    nickname?: string
162→  ): Promise<void> {
163→    const foundPath = await findSubagentFile(
164→      this.config.sessionDateDir,
165→      agentId
166→    );
167→
168→    // Guard：stop() 後捨棄結果，避免向舊 watcher 注入資料
169→    if (this.stopped) return;
170→
171→    if (!foundPath) {
172→      this.config.output.warn(
173→        `Codex subagent file not found after retries: ${agentId}`
174→      );
175→      return;
176→    }
177→
178→    // Cleanup pending
179→    clearTimeout(pending.timer);
180→    this.pendingSpawns.delete(callId);
181→
182→    // 記錄已知 agent（供 handleSubagentResume 查詢路徑）
183→    this.registeredAgentPaths.set(agentId, foundPath);
184→
185→    // Guard：addFile 前再次確認未停止（watcher 是 let 閉包，可能已換新實例）
186→    if (this.stopped) return;
187→
188→    const label = makeCodexAgentLabel(agentId);
189→    await this.config.watcher.addFile({ path: foundPath, label });
190→
191→    // Guard：addFile 是 async，完成後再確認一次，防止 onNewSubagent 對已切換的 session 觸發
192→    if (this.stopped) return;
193→
194→    const description = nickname
195→      ? `${nickname} (${pending.agentType || 'agent'})`
196→      : pending.agentType && pending.message
197→        ? `${pending.agentType}: ${pending.message.slice(0, 50)}`
198→        : undefined;
199→    this.config.onNewSubagent?.(agentId, foundPath, description);
200→  }
201→
202→  handleSubagentResume(agentId: string): void {
203→    if (!this.config.enabled) return;
204→    if (!isValidCodexAgentId(agentId)) return;
205→
206→    const path = this.registeredAgentPaths.get(agentId);
207→    if (path) {
208→      this.config.onSubagentEnter?.(agentId, path);
209→    }
210→  }
211→
212→  getAgentPath(agentId: string): string | undefined {
213→    return this.registeredAgentPaths.get(agentId);
214→  }
215→
216→  handleSubagentDone(agentId: string): void {
217→    this.config.onSubagentDone?.(agentId);
218→  }
219→
220→  stop(): void {
221→    this.stopped = true;
222→    for (const pending of this.pendingSpawns.values()) {
223→      clearTimeout(pending.timer);
224→    }
225→    this.pendingSpawns.clear();
226→    this.registeredAgentPaths.clear();
227→  }
228→}
