  5→
  6→/** MVP 最大 pane 數量（安全上限，Phase 2 可設定） */
  7→const MAX_PANES = 6;
  8→
  9→/** Pane title description 最大長度 */
 10→const MAX_DESCRIPTION_LENGTH = 50;
 11→
 12→/**
 13→ * 清理並格式化 pane title
 14→ * - 移除 control characters 和 tmux # 特殊序列
 15→ * - 截斷超長描述
 16→ */
 17→function sanitizePaneTitle(description: string): string {
 18→  return (
 19→    description
 20→      // eslint-disable-next-line no-control-regex
 21→      .replace(/[\x00-\x1f\x7f]/g, ' ') // control chars -> space
 22→      .replace(/#/g, '') // tmux interprets #() sequences
 23→      .trim()
 24→      .slice(0, MAX_DESCRIPTION_LENGTH)
 25→  );
 26→}
 27→
 28→/** applyLayout debounce 延遲（ms） */
 29→const LAYOUT_DEBOUNCE_MS = 50;
 30→
 31→/**
 32→ * Pane 生命週期管理器
 33→ *
 34→ * 負責追蹤所有開啟的 pane，並在需要時統一清理。
 35→ * 是 pane 狀態的唯一 source of truth。
 36→ */
 37→export class PaneManager {
 38→  private controller: TerminalController;
 39→  private commandBuilder: (agentId: string, subagentPath: string) => string;
 40→  private logger?: (msg: string) => void;
 41→  private panes: Map<string, PaneInfo> = new Map(); // agentId -> PaneInfo
 42→  /** 正在開啟中的 agentId（防止併發超開） */
 43→  private pendingAgentIds: Set<string> = new Set();
 44→  /** 待關閉的 agentId（pane 還在 pending 時就收到 done 事件） */
 45→  private pendingCloseAgentIds: Set<string> = new Set();
 46→  /** applyLayout debounce timer */
 47→  private layoutTimer: ReturnType<typeof setTimeout> | null = null;
 48→
 49→  constructor(
 50→    controller: TerminalController,
 51→    commandBuilder: (agentId: string, subagentPath: string) => string,
 52→    logger?: (msg: string) => void
 53→  ) {
 54→    this.controller = controller;
 55→    this.commandBuilder = commandBuilder;
 56→    this.logger = logger;
 57→  }
 58→
 59→  /**
 60→   * 為 subagent 開啟新 pane
 61→   * - 已存在相同 agentId 的 pane 時跳過（去重）
 62→   * - 超過 MAX_PANES 時跳過（安全上限）
 63→   * - 使用 pendingAgentIds 防止併發呼叫超開
 64→   * - description 用於命名 pane（可選，來自 Task tool_use 的 description 欄位）
 65→   */
 66→  async openPane(
 67→    agentId: string,
 68→    subagentPath: string,
 69→    description?: string
 70→  ): Promise<void> {
 71→    if (this.panes.has(agentId)) return;
 72→    if (this.pendingAgentIds.has(agentId)) return;
 73→    if (this.panes.size + this.pendingAgentIds.size >= MAX_PANES) return;
 74→
 75→    this.pendingAgentIds.add(agentId);
 76→    this.logger?.(`[pane] Opening pane for ${agentId}...`);
 77→    try {
 78→      const cmd = this.commandBuilder(agentId, subagentPath);
 79→      const pane = await this.controller.createPane(cmd, agentId);
 80→      if (pane) {
 81→        this.panes.set(agentId, pane);
 82→
 83→        // Best-effort pane naming (before pendingClose check)
 84→        if (description && this.controller.renamePane) {
 85→          const title = sanitizePaneTitle(description);
 86→          try {
 87→            await this.controller.renamePane(pane.id, title);
 88→          } catch {
 89→            // 命名失敗不影響 pane 功能
 90→          }
 91→        }
 92→
 93→        // 排程佈局更新（debounce，連續開多個 pane 時只觸發一次）
 94→        this.scheduleLayout();
 95→
 96→        // 檢查是否在 pending 期間收到了 done 事件
 97→        if (this.pendingCloseAgentIds.has(agentId)) {
 98→          this.pendingCloseAgentIds.delete(agentId);
 99→          // 立刻關閉這個 pane
100→          await this.closePaneByAgentId(agentId);
101→        }
102→      } else {
103→        // createPane 失敗，清除待關閉狀態（沒有 pane 就不需要關閉）
104→        this.pendingCloseAgentIds.delete(agentId);
105→      }
106→    } catch (e) {
107→      // 非預期錯誤（如 commandBuilder throw），清理所有相關狀態後向外拋出
108→      this.pendingCloseAgentIds.delete(agentId);
109→      throw e;
110→    } finally {
111→      this.pendingAgentIds.delete(agentId);
112→    }
113→  }
114→
115→  /**
116→   * 關閉所有已追蹤的 pane（best-effort）
117→   */
118→  async closeAll(): Promise<void> {
119→    this.clearLayoutTimer();
120→    const closePromises = [...this.panes.values()].map((p) =>
121→      this.controller.closePane(p.id).catch(() => {})
122→    );
123→    await Promise.all(closePromises);
124→    this.panes.clear();
125→    this.pendingCloseAgentIds.clear();
126→  }
127→
128→  /**
129→   * 排程佈局更新（debounce）
130→   * 連續開多個 pane 時只在最後觸發一次 tmux select-layout
131→   */
132→  private scheduleLayout(): void {
133→    this.clearLayoutTimer();
134→    this.layoutTimer = setTimeout(() => {
135→      this.layoutTimer = null;
136→      this.applyLayout().catch(() => {});
137→    }, LAYOUT_DEBOUNCE_MS);
138→  }
139→
140→  private clearLayoutTimer(): void {
141→    if (this.layoutTimer) {
142→      clearTimeout(this.layoutTimer);
143→      this.layoutTimer = null;
144→    }
145→  }
146→
147→  /**
148→   * 套用佈局（如果 controller 支援）
149→   * Best-effort 操作，失敗不影響核心功能
150→   */
151→  private async applyLayout(): Promise<void> {
152→    if (this.controller.applyLayout) {
153→      try {
154→        await this.controller.applyLayout('main-vertical');
155→      } catch {
156→        // 靜默忽略佈局失敗
157→      }
158→    }
159→  }
160→
161→  /**
162→   * 根據 agentId 關閉對應的 pane
163→   * Best-effort 操作，失敗不影響核心功能
164→   * 如果 pane 還在 pending，會標記為待關閉，等 pane 建立後自動關閉
165→   */
166→  async closePaneByAgentId(agentId: string): Promise<void> {
167→    // 如果 pane 還在開啟中，標記為待關閉
168→    if (this.pendingAgentIds.has(agentId) && !this.panes.has(agentId)) {
169→      this.pendingCloseAgentIds.add(agentId);
170→      return;
171→    }
172→
173→    const pane = this.panes.get(agentId);
174→    if (!pane) return;
175→
176→    this.logger?.(`[pane] Closing pane for ${agentId}...`);
177→
178→    // 立刻移除，防止並行呼叫重複觸發 closePane
179→    this.panes.delete(agentId);
180→
181→    try {
182→      await this.controller.closePane(pane.id);
183→    } catch {
184→      // 靜默忽略關閉失敗（pane 可能已經關閉）
185→    }
186→  }
187→
188→  /**
189→   * 目前開啟的 pane 數量
190→   */
191→  get activePaneCount(): number {
192→    return this.panes.size;
193→  }
194→
195→  /**
196→   * 檢查指定 agentId 是否有對應的 pane（包含 pending 狀態）
197→   * 用於判斷是否需要觸發 onSubagentDone
198→   */
199→  hasPaneForAgent(agentId: string): boolean {
200→    return this.panes.has(agentId) || this.pendingAgentIds.has(agentId);
201→  }
202→}
203→

100→  // 找到目標 session 檔案
101→  let sessionFile: SessionFile | null = null;
102→  let subagentFile: SessionFile | null = null; // Claude subagent 關聯
103→
104→  // 判斷搜尋模式
105→  if (options.sessionId) {
106→    // 使用 sessionId 搜尋特定 session
107→    log(
108→      options.quiet,
109→      chalk.gray(
110→        `Searching for ${options.agentType} session "${options.sessionId}"...`
111→      )
112→    );
113→
114→    const finder = agent.finder;
115→    if (!finder.findBySessionId) {
116→      console.error(
117→        chalk.red(
118→          `Session ID lookup not supported for ${options.agentType} agent`
119→        )
120→      );
121→      process.exit(1);
122→    }
123→
124→    const result = await finder.findBySessionId(options.sessionId, {
125→      project: options.project,
126→    });
127→
128→    if (!result) {
129→      const projectInfo = options.project
130→        ? ` in project "${options.project}"`
131→        : '';
132→      console.error(
133→        chalk.red(
134→          `No session found matching "${options.sessionId}"${projectInfo}`
135→        )
136→      );
137→      process.exit(1);
138→    }
139→
140→    // 判斷是否為 ClaudeSessionResult（有 main 和 subagent）
141→    if ('main' in result && 'subagent' in result) {
142→      const claudeResult = result as ClaudeSessionResult;
143→      sessionFile = claudeResult.main;
144→      subagentFile = claudeResult.subagent || null;
145→      log(
146→        options.quiet,
147→        chalk.green(`Found main session: ${sessionFile.path}`)
148→      );
149→      if (subagentFile) {
150→        log(options.quiet, chalk.green(`Found subagent: ${subagentFile.path}`));
151→      }
152→    } else {
153→      sessionFile = result as SessionFile;
154→      log(options.quiet, chalk.green(`Found: ${sessionFile.path}`));
155→    }
156→    logSessionMeta(sessionFile, options.quiet);
157→  } else if (
158→    (options.agentType === 'claude' || options.agentType === 'codex') &&
159→    options.subagent !== undefined
160→  ) {
161→    // Claude/Codex subagent 模式（使用 --subagent 選項）
162→    log(
163→      options.quiet,
164→      chalk.gray(`Searching for latest ${options.agentType} subagent...`)
165→    );
166→
167→    const finder = agent.finder;
168→    if (finder.findSubagent) {
169→      const subagentId =
170→        typeof options.subagent === 'string' ? options.subagent : undefined;
171→
172→      sessionFile = await finder.findSubagent({
173→        project: options.project,
174→        subagentId,
175→      });
176→
177→      if (!sessionFile) {
178→        const idInfo = subagentId ? ` (id: ${subagentId})` : '';
179→        const projectInfo = options.project
180→          ? ` in project "${options.project}"`
181→          : '';
182→        console.error(
183→          chalk.red(`No subagent file found${idInfo}${projectInfo}`)
184→        );
185→        process.exit(1);
186→      }
187→    }
188→    log(options.quiet, chalk.green(`Found: ${sessionFile?.path}`));
189→    log(
190→      options.quiet,
191→      chalk.gray(`Modified: ${sessionFile?.mtime.toLocaleString()}`)
192→    );
193→  } else {
194→    // 預設模式：找最新的 session
195→    log(
196→      options.quiet,
197→      chalk.gray(`Searching for latest ${options.agentType} session...`)
198→    );
199→

200→    sessionFile = await agent.finder.findLatest({
201→      project: options.project,
202→    });
203→
204→    if (!sessionFile) {
205→      console.error(
206→        chalk.red(
207→          `No session file found for ${options.agentType}${options.project ? ` (project: ${options.project})` : ''}`
208→        )
209→      );
210→      process.exit(1);
211→    }
212→
213→    log(options.quiet, chalk.green(`Found: ${sessionFile.path}`));
214→    logSessionMeta(sessionFile, options.quiet);
215→  }
216→
217→  if (!sessionFile) {
218→    console.error(chalk.red('No session file found'));
219→    process.exit(1);
220→  }
221→
222→  // 監控模式判斷：
223→  // 1. Claude 主 session 模式 → Claude 多檔案監控
224→  // 2. Codex 主 session + withSubagents/pane → Codex 多檔案監控
225→  // 3. --subagent 選項 → 單檔案監控（Claude/Codex）
226→  // 4. 其他 agent → 單檔案監控
227→  if (options.agentType === 'claude' && options.subagent === undefined) {
228→    if (options.interactive) {
229→      // Interactive 模式：使用 SessionManager 管理輸出切換
230→      await startClaudeInteractiveWatch(
231→        sessionFile,
232→        formatter,
233→        options,
234→        subagentFile
235→      );
236→    } else {
237→      // 普通模式：所有來源輸出到 console
238→      await startClaudeMultiWatch(
239→        sessionFile,
240→        formatter,
241→        options,
242→        subagentFile
243→      );
244→    }
245→  } else if (options.agentType === 'codex' && options.interactive) {
246→    // Codex 互動模式（Phase 3）
247→    await startCodexInteractiveWatch(sessionFile, formatter, options);
248→  } else if (
249→    options.agentType === 'codex' &&
250→    options.subagent === undefined &&
251→    (options.withSubagents || options.pane)
252→  ) {
253→    // Codex 多檔案監控（主 session + subagents）
254→    await startCodexMultiWatch(sessionFile, formatter, options);
255→  } else {
256→    // 其他 agent 或 Claude/Codex subagent 模式：單檔案監控
257→    await startSingleWatch(agent, sessionFile, formatter, options);
258→  }
259→}
260→
261→/**
262→ * Claude 多檔案監控（主 session + subagents）
263→ * @param initialSubagent - 從 sessionId 參數指定的 subagent（可選）
264→ */
265→async function startClaudeMultiWatch(
266→  sessionFile: SessionFile,
267→  formatter: Formatter,
268→  options: CliOptions,
269→  initialSubagent: SessionFile | null = null
270→): Promise<void> {
271→  const projectDir = dirname(sessionFile.path);
272→  let subagentsDir = getSubagentsDir(sessionFile.path);
273→
274→  // 建立監控檔案列表（主 session）
275→  const files: WatchedFile[] = [{ path: sessionFile.path, label: MAIN_LABEL }];
276→
277→  // 只有在 withSubagents 為 true 時才掃描 subagent
278→  const existingAgentIds = new Set<string>();
279→  if (options.withSubagents) {
280→    // 掃描現有的 subagent（優先使用目錄掃描，確保找到所有檔案）
281→    const dirAgentIds = await scanForNewSubagents(subagentsDir, new Set());
282→    for (const id of dirAgentIds) {
283→      existingAgentIds.add(id);
284→    }
285→
286→    // 如果有從 sessionId 指定的 subagent，確保它被加入
287→    if (initialSubagent) {
288→      const initialAgentId = basename(initialSubagent.path, '.jsonl').replace(
289→        /^agent-/,
290→        ''
291→      );
292→      existingAgentIds.add(initialAgentId);
293→    }
294→
295→    const existingSubagentFiles = await buildSubagentFiles(
296→      subagentsDir,
297→      existingAgentIds
298→    );
299→    for (const { agentId, path } of existingSubagentFiles) {
300→      files.push({ path, label: makeAgentLabel(agentId) });
301→    }
302→
303→    if (existingAgentIds.size > 0) {
304→      log(
305→        options.quiet,
306→        chalk.gray(`Found ${existingAgentIds.size} subagent(s)`)
307→      );
308→    }
309→  }
310→  log(options.quiet, chalk.gray('---'));
311→
312→  // 為每個來源建立獨立的 parser
313→  let parsers = new Map<string, LineParser>();
314→  for (const file of files) {
315→    const parserAgent = new ClaudeAgent({ verbose: options.verbose });
316→    parsers.set(file.label, parserAgent.parser);
317→  }
318→
319→  // 非 follow 模式且有 subagent：收集所有行後按時間排序輸出
320→  if (!options.follow && options.withSubagents && files.length > 1) {
321→    await outputTimeSorted(files, parsers, formatter, options);
322→    process.exit(0);
323→  }
324→
325→  let multiWatcher = new MultiFileWatcher();
326→
327→  // 建立 PaneManager（--pane 模式時自動開啟 tmux pane）
328→  let paneManager: PaneManager | null = null;
329→  if (options.pane) {
330→    const controller = createTerminalController();
331→    if (controller.isAvailable()) {
332→      paneManager = new PaneManager(
333→        controller,
334→        (agentId, _subagentPath) => {
335→          // 使用當前執行方式重建指令（支援 bun run、npx、全域安裝等）
336→          // 用雙引號包覆路徑，防止空格造成 shell 指令斷裂
337→          const runtime = `"${process.argv[0]}"`;
338→          const script = `"${process.argv[1]}"`;
339→          return `${runtime} ${script} claude --subagent ${agentId} -q --no-pane`;
340→        },
341→        (msg) => log(options.quiet, chalk.gray(msg))
342→      );
343→    } else {
344→      log(
345→        options.quiet,
346→        chalk.yellow('Warning: tmux not detected, --pane disabled')
347→      );
348→    }
349→  }

350→
351→  // 提取 pane 相關回呼（消除 paneManager! 斷言，用 const 捕獲確認非 null 的參照）
352→  const pm = paneManager; // 閉包捕獲，不受外部重賦值影響
353→  const openPaneForSubagent = pm
354→    ? (agentId: string, subagentPath: string, description?: string) => {
355→        pm.openPane(agentId, subagentPath, description).catch((err) => {
356→          log(
357→            options.quiet,
358→            chalk.yellow(`[pane] Failed to open pane: ${err}`)
359→          );
360→        });
361→      }
362→    : undefined;
363→
364→  const onSubagentDone = pm
365→    ? (agentId: string) => {
366→        const subagentPath = buildSubagentPath(subagentsDir, agentId);
367→
368→        // 先讀取並輸出最後的 assistant 訊息，再關閉 pane
369→        (async () => {
370→          try {
371→            const parts = await readLastAssistantMessage(
372→              subagentPath,
373→              options.verbose
374→            );
375→            const label = makeAgentLabel(agentId);
376→            for (const part of parts) {
377→              part.sourceLabel = label;
378→              console.log(formatter.format(part));
379→            }
380→          } catch {
381→            // 讀取失敗不影響 pane 關閉
382→          } finally {
383→            await pm.closePaneByAgentId(agentId);
384→          }
385→        })().catch(() => {});
386→      }
387→    : undefined;
388→
389→  const hasPaneCallback = pm
390→    ? (agentId: string) => pm.hasPaneForAgent(agentId)
391→    : undefined;
392→
393→  // pane 模式下，進入時既有 subagent 加入 suppress set，避免歷史內容污染 main pane
394→  const suppressedForPane = pm ? new Set(existingAgentIds) : new Set<string>();
395→
396→  const shouldOutput = pm
397→    ? (label: string) => {
398→        if (label === MAIN_LABEL) return true;
399→        const agentId = extractAgentIdFromLabel(label);
400→        if (suppressedForPane.has(agentId)) return false;
401→        return !pm.hasPaneForAgent(agentId);
402→      }
403→    : undefined;
404→
405→  // 建立 SubagentDetector（整合 early detection 和 fallback detection）
406→  let detector = new SubagentDetector(existingAgentIds, {
407→    subagentsDir,
408→    output: new ConsoleOutputHandler(),
409→    watcher: { addFile: (f) => multiWatcher.addFile(f) },
410→    session: new NoOpSessionHandler(),
411→    enabled: options.follow && options.withSubagents,
412→    onNewSubagent: openPaneForSubagent,
413→    onSubagentEnter: openPaneForSubagent,
414→    onSubagentDone,
415→    hasPane: hasPaneCallback,
416→  });
417→  detector.startDirectoryWatch();
418→
419→  // ========== Non-Interactive Super-Follow ==========
420→  let currentSessionPath = sessionFile.path;
421→
422→  const switchToSession = async (
423→    nextSessionFile: SessionFile
424→  ): Promise<void> => {
425→    // 停止現有監控
426→    detector?.stop();
427→    multiWatcher.stop();
428→
429→    // 更新當前 session 路徑
430→    currentSessionPath = nextSessionFile.path;
431→
432→    // 重新初始化監控
433→    const newSessionId = basename(nextSessionFile.path, '.jsonl');
434→    const newSubagentsDir = getSubagentsDir(nextSessionFile.path);
435→
436→    const newFiles: WatchedFile[] = [
437→      { path: nextSessionFile.path, label: MAIN_LABEL },
438→    ];
439→    const newExistingAgentIds = new Set<string>();
440→
441→    // 掃描現有的 subagents
442→    if (options.withSubagents) {
443→      const dirAgentIds = await scanForNewSubagents(newSubagentsDir, new Set());
444→      for (const id of dirAgentIds) {
445→        newExistingAgentIds.add(id);
446→      }
447→
448→      const existingSubagentFiles = await buildSubagentFiles(
449→        newSubagentsDir,
450→        newExistingAgentIds
451→      );
452→      for (const { agentId, path } of existingSubagentFiles) {
453→        newFiles.push({ path, label: makeAgentLabel(agentId) });
454→      }
455→
456→      if (newExistingAgentIds.size > 0) {
457→        log(
458→          options.quiet,
459→          chalk.gray(`Found ${newExistingAgentIds.size} subagent(s)`)
460→        );
461→      }
462→    }
463→
464→    // 更新 suppress set：清空後填入新 session 的既有 subagent
465→    if (pm) {
466→      suppressedForPane.clear();
467→      for (const agentId of newExistingAgentIds) suppressedForPane.add(agentId);
468→    }
469→
470→    // 輸出切換訊息
471→    const switchTitle = await readCustomTitle(nextSessionFile.path);
472→    const switchTitleSuffix = switchTitle ? ` "${switchTitle}"` : '';
473→    log(
474→      options.quiet,
475→      chalk.gray(
476→        `--- Switched to session ${newSessionId}${switchTitleSuffix} ---`
477→      )
478→    );
479→    log(options.quiet, chalk.gray('---'));
480→
481→    // 重新建立 parsers
482→    const newParsers = new Map<string, LineParser>();
483→    for (const file of newFiles) {
484→      const parserAgent = new ClaudeAgent({ verbose: options.verbose });
485→      newParsers.set(file.label, parserAgent.parser);
486→    }
487→    parsers = newParsers;
488→
489→    // 重新建立 multiWatcher（先建立，但還不啟動）
490→    const newMultiWatcher = new MultiFileWatcher();
491→
492→    // 重新建立 detector（捕獲新的 multiWatcher，沿用 pane 回呼）
493→    const newDetector = new SubagentDetector(newExistingAgentIds, {
494→      subagentsDir: newSubagentsDir,
495→      output: new ConsoleOutputHandler(),
496→      watcher: { addFile: (f) => newMultiWatcher.addFile(f) },
497→      session: new NoOpSessionHandler(),
498→      enabled: options.follow && options.withSubagents,
499→      onNewSubagent: openPaneForSubagent,
500→      onSubagentEnter: openPaneForSubagent,
501→      onSubagentDone,
502→      hasPane: hasPaneCallback,
503→    });
504→    newDetector.startDirectoryWatch();
505→
506→    // 更新外層變數
507→    subagentsDir = newSubagentsDir;
508→    multiWatcher = newMultiWatcher;
509→    detector = newDetector;
510→
511→    // 重新啟動監控
512→    await multiWatcher.start(newFiles, {
