193→/**
194→ * createSuperFollowController 的配置
195→ */
196→export interface SuperFollowControllerConfig {
197→  projectDir: string;
198→  getCurrentPath: () => string;
199→  onSwitch: (nextFile: SessionFile) => Promise<void>;
200→  autoSwitch: boolean;
201→  /** 注入的 session 搜尋函數（用於尋找專案中最新的 session） */
202→  findLatestInProject: (projectDir: string) => Promise<SessionFile | null>;
203→}
204→
205→/**
206→ * 建立 super-follow 控制器（自動切換到最新 session）
207→ */
208→export function createSuperFollowController(
209→  config: SuperFollowControllerConfig
210→): {
211→  start: () => void;
212→  stop: () => void;
213→} {
214→  let stopped = false;
215→  let pendingSwitchPath: string | null = null;
216→  let pendingSwitchTimer: ReturnType<typeof setTimeout> | null = null;
217→  let pollTimer: ReturnType<typeof setTimeout> | null = null;
218→
219→  const clearPendingSwitch = (): void => {
220→    if (pendingSwitchTimer) {
221→      clearTimeout(pendingSwitchTimer);
222→      pendingSwitchTimer = null;
223→    }
224→    pendingSwitchPath = null;
225→  };
226→
227→  const scheduleSwitch = (nextPath: string): void => {
228→    if (pendingSwitchPath === nextPath) return;
229→    pendingSwitchPath = nextPath;
230→    if (pendingSwitchTimer) clearTimeout(pendingSwitchTimer);
231→
232→    pendingSwitchTimer = setTimeout(async () => {
233→      if (stopped || !pendingSwitchPath) return;
234→      try {
235→        const latest = await config.findLatestInProject(config.projectDir);
236→        if (
237→          latest &&
238→          latest.path === pendingSwitchPath &&
239→          latest.path !== config.getCurrentPath()
240→        ) {
241→          await config.onSwitch(latest);
242→        }
243→      } catch {
244→        // ignore
245→      } finally {
246→        clearPendingSwitch();
247→      }
248→    }, SUPER_FOLLOW_DELAY_MS);
249→  };
250→
251→  const start = (): void => {
252→    if (!config.autoSwitch) return;
253→
254→    const poll = async (): Promise<void> => {
255→      if (stopped) return;
256→      try {
257→        const latest = await config.findLatestInProject(config.projectDir);
258→        if (latest && latest.path !== config.getCurrentPath()) {
259→          scheduleSwitch(latest.path);
260→        } else if (!latest) {
261→          clearPendingSwitch();
262→        }
263→      } catch {
264→        // ignore
265→      } finally {
266→        pollTimer = setTimeout(poll, SUPER_FOLLOW_POLL_MS);
267→      }
268→    };
269→
270→    poll();
271→  };
272→
273→  const stop = (): void => {
274→    stopped = true;
275→    clearPendingSwitch();
276→    if (pollTimer) {
277→      clearTimeout(pollTimer);
278→      pollTimer = null;
279→    }
280→  };
281→
282→  return { start, stop };
283→}
