   * 專案模糊匹配
   * 匹配 workspace slug 或 .workspace-trusted 的 workspacePath
   */
  private async _matchProject(
    filePath: string,
    project: string,
    cache: Map<string, string | null>
  ): Promise<boolean> {
    const pattern = project.toLowerCase();

