} from './claude/session-handlers.ts';
import {
  buildSubagentFiles,
  createOnLineHandler,
  createSuperFollowController,
  readLastAssistantMessage,
} from './claude/watch-builder.ts';
import { findLatestMainSessionInProject } from './claude/auto-switch.ts';
