162→    const session = this.sessions[this.activeIndex] ?? null;
163→    if (session) {
164→      this.options.onSessionSwitched?.(session, this.sessions);
165→    }
166→
167→    return session;
168→  }
169→
170→  /**
171→   * 處理輸出
172→   * - active session: 直接輸出，同時存入 buffer（供切換後回看）
173→   * - 非 active session: 存入 buffer
174→   */
175→  handleOutput(label: string, content: string): void {
176→    const session = this.sessions.find((s) => s.label === label);
177→    if (!session) return;
178→
179→    const activeSession = this.getActiveSession();
180→
181→    // 所有 session 都存入 buffer（全量緩衝）
182→    session.buffer.push(content);
183→
184→    // 限制 buffer 大小
185→    if (session.buffer.length > this.bufferSize) {
186→      session.buffer.shift();
187→    }
188→
189→    // Active session 同時輸出到顯示
190→    if (session === activeSession) {
191→      this.options.onOutput(content, session);
192→    }
193→  }
194→
195→  /**
196→   * 取得 session 的緩衝內容（回傳 copy 以防止外部意外修改）
197→   */
198→  getSessionBuffer(id: string): string[] {
199→    const session = this.sessions.find((s) => s.id === id);
200→    return session?.buffer.slice() ?? [];
201→  }
202→
203→  /**
204→   * 清空 session 的緩衝
205→   */
206→  clearSessionBuffer(id: string): void {
207→    const session = this.sessions.find((s) => s.id === id);
208→    if (session) {
209→      session.buffer = [];
210→    }
211→  }
212→
213→  /**
214→   * 更新 session 的 displayName（例如 Claude custom-title 變更時）
215→   */
216→  updateSessionDisplayName(id: string, displayName: string): void {
217→    const session = this.sessions.find((s) => s.id === id);
218→    if (session) {
219→      session.displayName = displayName;
220→    }
221→  }
222→
223→  /**
224→   * 標記 session 為已結束
225→   */
226→  markSessionDone(id: string): void {
227→    const session = this.sessions.find((s) => s.id === id);
228→    if (session) {
229→      session.isDone = true;
230→    }
231→  }
232→
233→  /**
234→   * 輸出當前 active session 的緩衝內容（切換後顯示歷史）
235→   */
236→  flushActiveBuffer(): void {
237→    const session = this.getActiveSession();
238→    if (!session || session.buffer.length === 0) return;
239→
240→    for (const content of session.buffer) {
241→      this.options.onOutput(content, session);
242→    }
243→
244→    session.buffer = [];
245→  }
246→
247→  /**
248→   * 建立 WatchedFile 列表給 MultiFileWatcher 使用
249→   */
250→  getWatchedFiles(): WatchedFile[] {
251→    return this.sessions.map((s) => ({
252→      path: s.path,
253→      label: s.label,
254→    }));
255→  }
256→
257→  /**
258→   * Session 總數
259→   */
260→  get sessionCount(): number {
261→    return this.sessions.length;
262→  }
263→
264→  /**
265→   * 是否只有一個 session（無需切換）
266→   */
267→  get isSingleSession(): boolean {
268→    return this.sessions.length <= 1;
269→  }
270→}
