  1→import chalk from 'chalk';
  2→import type { WatcherSession } from '../core/session-manager.ts';
  3→
  4→/**
  5→ * DisplayController 選項
  6→ */
  7→export interface DisplayControllerOptions {
  8→  /** 是否啟用持久狀態列（需要 TTY） */
  9→  persistentStatusLine?: boolean;
 10→  /** 歷史回看時顯示的最大行數 */
 11→  historyLines?: number;
 12→}
 13→
 14→/**
 15→ * ANSI Escape Codes
 16→ */
 17→const ANSI = {
 18→  // 游標控制
 19→  saveCursor: '\x1b[s',
 20→  restoreCursor: '\x1b[u',
 21→  hideCursor: '\x1b[?25l',
 22→  showCursor: '\x1b[?25h',
 23→  // 行控制
 24→  clearLine: '\x1b[2K',
 25→  clearToEnd: '\x1b[K',
 26→  // 移動
 27→  moveToColumn: (n: number) => `\x1b[${n}G`,
 28→  moveUp: (n: number) => `\x1b[${n}A`,
 29→  moveDown: (n: number) => `\x1b[${n}B`,
 30→  moveToBottom: '\x1b[999B',
 31→  // 螢幕控制
 32→  scrollUp: '\x1b[S',
 33→  setScrollRegion: (top: number, bottom: number) => `\x1b[${top};${bottom}r`,
 34→  resetScrollRegion: '\x1b[r',
 35→};
 36→
 37→/**
 38→ * Display Controller - 控制終端輸出和狀態列顯示
 39→ *
 40→ * 用於 interactive mode，管理：
 41→ * - 持久狀態列（底部固定）
 42→ * - 內容輸出區域（狀態列上方）
 43→ * - 歷史回看顯示
 44→ */
 45→export class DisplayController {
 46→  private isInitialized = false;
 47→  private persistentStatusLine: boolean;
 48→  private historyLines: number;
 49→  private currentStatusLine = '';
 50→  private terminalRows: number;
 51→  private terminalCols: number;
 52→  // 保存 handler 引用以便在 destroy() 時移除
 53→  private onResize = () => {
 54→    this.terminalRows = process.stdout.rows || 24;
 55→    this.terminalCols = process.stdout.columns || 80;
 56→    if (
 57→      this.isInitialized &&
 58→      this.persistentStatusLine &&
 59→      process.stdout.isTTY
 60→    ) {
 61→      // 重設 scroll region 以適應新的終端大小
 62→      process.stdout.write(ANSI.setScrollRegion(1, this.terminalRows - 1));
 63→      // 移動游標到內容區
 64→      process.stdout.write(`\x1b[${this.terminalRows - 1};1H`);
 65→      // 刷新狀態列
 66→      this.refreshStatusLine();
 67→    }
 68→  };
 69→
 70→  constructor(options: DisplayControllerOptions = {}) {
 71→    this.persistentStatusLine = options.persistentStatusLine ?? true;
 72→    this.historyLines = options.historyLines ?? 50;
 73→    this.terminalRows = process.stdout.rows || 24;
 74→    this.terminalCols = process.stdout.columns || 80;
 75→
 76→    // 監聽終端大小變化
 77→    process.stdout.on('resize', this.onResize);
 78→  }
 79→
 80→  /**
 81→   * 初始化 DisplayController
 82→   */
 83→  init(): void {
 84→    if (this.isInitialized) return;
 85→
 86→    if (this.persistentStatusLine && process.stdout.isTTY) {
 87→      // 設定捲動區域（保留最後一行給狀態列）
 88→      process.stdout.write(ANSI.setScrollRegion(1, this.terminalRows - 1));
 89→      // 移到捲動區域內
 90→      process.stdout.write(`\x1b[${this.terminalRows - 1};1H`);
 91→      // 顯示初始狀態列
 92→      this.refreshStatusLine();
 93→    }
 94→
 95→    this.isInitialized = true;
 96→  }
 97→
 98→  /**
 99→   * 清理並恢復終端設定
100→   */
101→  destroy(): void {
102→    if (!this.isInitialized) return;
103→
104→    // 移除 resize 監聽器
105→    process.stdout.off('resize', this.onResize);
106→
107→    if (this.persistentStatusLine && process.stdout.isTTY) {
108→      // 清除狀態列
109→      process.stdout.write(`\x1b[${this.terminalRows};1H`);
110→      process.stdout.write(ANSI.clearLine);
111→      // 重設捲動區域
112→      process.stdout.write(ANSI.resetScrollRegion);
113→      // 顯示游標
114→      process.stdout.write(ANSI.showCursor);
115→    }
116→
117→    this.isInitialized = false;
118→  }
119→
120→  /**
121→   * 輸出內容到終端（確保不覆蓋狀態列）
122→   */
123→  write(content: string): void {
124→    if (this.persistentStatusLine && process.stdout.isTTY) {
125→      // 確保在捲動區域內輸出
126→      process.stdout.write(content + '\n');
127→    } else {
128→      // 非 TTY 模式直接輸出
129→      console.log(content);
130→    }
131→  }
132→
133→  /**
134→   * 更新狀態列
135→   */
136→  updateStatusLine(sessions: WatcherSession[], activeIndex: number): void {
137→    const statusLine = this.buildStatusLine(sessions, activeIndex);
138→    this.currentStatusLine = statusLine;
139→
140→    if (this.persistentStatusLine && process.stdout.isTTY) {
141→      this.refreshStatusLine();
142→    } else {
143→      // 非 TTY 模式用分隔線顯示
144→      console.log(statusLine);
145→    }
146→  }
147→
148→  /**
149→   * 建構狀態列內容
150→   */
151→  private buildStatusLine(
152→    sessions: WatcherSession[],
153→    activeIndex: number
154→  ): string {
155→    const total = sessions.length;
156→
157→    // 位置指示器 [3/20]
158→    const positionIndicator = chalk.cyan(`[${activeIndex + 1}/${total}]`);
159→
160→    // 計算滑動視窗範圍（顯示 active 附近的 5 個 session）
161→    const windowSize = 5;
162→    const halfWindow = Math.floor(windowSize / 2);
163→
164→    let startIndex = Math.max(0, activeIndex - halfWindow);
165→    let endIndex = Math.min(total, startIndex + windowSize);
166→
167→    // 如果接近尾端，調整起始位置
168→    if (endIndex === total && total > windowSize) {
169→      startIndex = Math.max(0, total - windowSize);
170→    }
171→    // 如果接近開頭，調整結束位置
172→    if (startIndex === 0 && total > windowSize) {
173→      endIndex = Math.min(total, windowSize);
174→    }
175→
176→    const hiddenLeft = startIndex;
177→    const hiddenRight = total - endIndex;
178→
179→    // 建立可見 session 的顯示
180→    const visibleSessions = sessions.slice(startIndex, endIndex);
181→    const parts = visibleSessions.map((session, i) => {
182→      const actualIndex = startIndex + i;
183→      const isActive = actualIndex === activeIndex;
184→      const label = session.label.replace(/\[|\]/g, '');
185→      const displayLabel =
186→        session.displayName || (session.id === 'main' ? 'MAIN' : label);
187→      const bufferCount = session.buffer.length;
188→      const doneMarker = session.isDone ? chalk.green('✓') : '';
189→
190→      if (isActive) {
191→        return (
192→          chalk.cyan.bold(`[${displayLabel}]`) +
193→          (doneMarker ? chalk.green(doneMarker) : '')
194→        );
195→      } else {
196→        const bufferInfo =
197→          bufferCount > 0 ? chalk.yellow(`(${bufferCount})`) : '';
198→        return (
199→          chalk.gray(displayLabel) +
200→          (bufferInfo ? bufferInfo : '') +
201→          (doneMarker ? chalk.green(doneMarker) : '')
202→        );
203→      }
204→    });
205→
206→    // 組合狀態列
207→    let sessionsPart = '';
208→
209→    // 左側隱藏指示
210→    if (hiddenLeft > 0) {
211→      sessionsPart += chalk.yellow(`←${hiddenLeft}`) + chalk.gray(' | ');
212→    }
213→
214→    // 可見的 sessions
215→    sessionsPart += parts.join(chalk.gray(' | '));
216→
217→    // 右側隱藏指示
218→    if (hiddenRight > 0) {
219→      sessionsPart += chalk.gray(' | ') + chalk.yellow(`${hiddenRight}→`);
220→    }
221→
222→    const hint = chalk.gray(' (Tab/q)');
223→    const prefix = '─── ';
224→    const suffix = ' ───';
225→
226→    return (
227→      chalk.gray(prefix) +
228→      positionIndicator +
229→      ' ' +
230→      sessionsPart +
231→      hint +
232→      chalk.gray(suffix)
233→    );
234→  }
235→
236→  /**
237→   * 重繪狀態列
238→   */
239→  private refreshStatusLine(): void {
240→    if (!process.stdout.isTTY) return;
241→
242→    // 保存游標位置
243→    process.stdout.write(ANSI.saveCursor);
244→    // 移到最後一行
245→    process.stdout.write(`\x1b[${this.terminalRows};1H`);
246→    // 清除行
247→    process.stdout.write(ANSI.clearLine);
248→    // 輸出狀態列（截斷至終端寬度）
249→    const statusLine = this.truncateToWidth(
250→      this.currentStatusLine,
251→      this.terminalCols
252→    );
253→    process.stdout.write(statusLine);
254→    // 恢復游標位置
255→    process.stdout.write(ANSI.restoreCursor);
256→  }
257→
258→  /**
259→   * 顯示切換訊息和歷史內容
260→   */
261→  showSwitchMessage(session: WatcherSession, historyContent: string[]): void {
262→    // 顯示分隔線（包含完成狀態）
263→    const doneStatus = session.isDone ? chalk.green(' ✓ (completed)') : '';
264→    const switchLabel = session.displayName
265→      ? `${session.label} "${session.displayName}"`
266→      : session.label;
267→    const separator =
268→      chalk.gray(`\n─── Switched to ${switchLabel}`) +
269→      doneStatus +
270→      chalk.gray(` ───`);
271→    this.write(separator);
272→
273→    // 顯示歷史內容（最近 N 行）
274→    const linesToShow = historyContent.slice(-this.historyLines);
275→    if (linesToShow.length > 0) {
276→      const historyHeader = chalk.gray(
277→        `[Showing ${linesToShow.length} buffered lines]`
278→      );
279→      this.write(historyHeader);
280→      for (const line of linesToShow) {
281→        this.write(line);
282→      }
283→      const historyFooter = chalk.gray(`[End of buffer]`);
284→      this.write(historyFooter);
285→    } else {
286→      // Buffer 是空的，顯示提示訊息
287→      if (session.isDone) {
288→        this.write(chalk.gray(`[No new content - session completed]`));
289→      } else {
290→        this.write(
291→          chalk.gray(`[No buffered content - waiting for new output...]`)
292→        );
293→      }
294→    }
295→  }
296→
297→  /**
298→   * 截斷字串至指定寬度（考慮 ANSI codes）
299→   */
300→  private truncateToWidth(str: string, maxWidth: number): string {
301→    // 移除 ANSI codes 計算實際長度
302→    // eslint-disable-next-line no-control-regex
303→    const plainStr = str.replace(/\x1b\[[0-9;]*m/g, '');
304→    if (plainStr.length <= maxWidth) {
305→      return str;
306→    }
307→
308→    // 簡單截斷（不完美但足夠用）
309→    let visibleLength = 0;
310→    let result = '';
311→    let inEscape = false;
312→
313→    for (const char of str) {
314→      if (char === '\x1b') {
315→        inEscape = true;
316→        result += char;
317→      } else if (inEscape) {
318→        result += char;
319→        if (char === 'm') {
320→          inEscape = false;
321→        }
322→      } else {
323→        if (visibleLength >= maxWidth - 3) {
324→          result += '...';
325→          break;
326→        }
327→        result += char;
328→        visibleLength++;
329→      }
330→    }
331→
332→    return result;
333→  }
334→
335→  /**
336→   * 是否支援持久狀態列
337→   */
338→  get supportsPersistentStatusLine(): boolean {
339→    return process.stdout.isTTY === true;
340→  }
341→}
