278→/**
279→ * Claude 多檔案監控（主 session + subagents）
280→ * @param initialSubagent - 從 sessionId 參數指定的 subagent（可選）
281→ */
282→async function startClaudeMultiWatch(
283→  sessionFile: SessionFile,
284→  formatter: Formatter,
285→  options: CliOptions,
286→  initialSubagent: SessionFile | null = null
287→): Promise<void> {
288→  const projectDir = dirname(sessionFile.path);
289→  let subagentsDir = getSubagentsDir(sessionFile.path);
290→
291→  // 建立監控檔案列表（主 session）
292→  const files: WatchedFile[] = [{ path: sessionFile.path, label: MAIN_LABEL }];
293→
294→  // 只有在 withSubagents 為 true 時才掃描 subagent
295→  const existingAgentIds = new Set<string>();
296→  if (options.withSubagents) {
297→    // 掃描現有的 subagent（優先使用目錄掃描，確保找到所有檔案）
298→    const dirAgentIds = await scanForNewSubagents(subagentsDir, new Set());
299→    for (const id of dirAgentIds) {
300→      existingAgentIds.add(id);
301→    }
302→
303→    // 如果有從 sessionId 指定的 subagent，確保它被加入
304→    if (initialSubagent) {
305→      const initialAgentId = basename(initialSubagent.path, '.jsonl').replace(
306→        /^agent-/,
307→        ''
308→      );
309→      existingAgentIds.add(initialAgentId);
310→    }
311→
312→    const existingSubagentFiles = await buildSubagentFiles(
313→      subagentsDir,
314→      existingAgentIds
315→    );
316→    for (const { agentId, path } of existingSubagentFiles) {
317→      files.push({ path, label: makeAgentLabel(agentId) });
318→    }
319→
320→    if (existingAgentIds.size > 0) {
321→      log(
322→        options.quiet,
323→        chalk.gray(`Found ${existingAgentIds.size} subagent(s)`)
324→      );
325→    }
326→  }
327→  log(options.quiet, chalk.gray('---'));
328→
329→  // 為每個來源建立獨立的 parser
330→  let parsers = new Map<string, LineParser>();
331→  for (const file of files) {
332→    const parserAgent = new ClaudeAgent({ verbose: options.verbose });
333→    parsers.set(file.label, parserAgent.parser);
334→  }
335→
336→  // 非 follow 模式且有 subagent：收集所有行後按時間排序輸出
337→  if (!options.follow && options.withSubagents && files.length > 1) {
338→    await outputTimeSorted(files, parsers, formatter, options);
339→    process.exit(0);
340→  }
341→
342→  let multiWatcher = new MultiFileWatcher();
343→
344→  // 建立 PaneManager（--pane 模式時自動開啟 tmux pane）
345→  let paneManager: PaneManager | null = null;
346→  if (options.pane) {
347→    const controller = createTerminalController();
348→    if (controller.isAvailable()) {
349→      paneManager = new PaneManager(
350→        controller,
351→        (agentId, _subagentPath) => {
352→          // 使用當前執行方式重建指令（支援 bun run、npx、全域安裝等）
353→          // 用雙引號包覆路徑，防止空格造成 shell 指令斷裂
354→          const runtime = `"${process.argv[0]}"`;
355→          const script = `"${process.argv[1]}"`;
356→          return `${runtime} ${script} claude --subagent ${agentId} -q --no-pane`;
357→        },
358→        (msg) => log(options.quiet, chalk.gray(msg))
359→      );
360→    } else {
361→      log(
362→        options.quiet,
363→        chalk.yellow('Warning: tmux not detected, --pane disabled')
364→      );
365→    }
366→  }
367→
368→  // 提取 pane 相關回呼（消除 paneManager! 斷言，用 const 捕獲確認非 null 的參照）
