 29→
 30→/**
 31→ * Cursor Subagent 偵測器
 32→ *
 33→ * 純目錄監控模式（Cursor JSONL 無 subagent spawn/resume 事件）。
 34→ * 透過 fs.watch 監控 subagents/ 目錄變化，偵測新檔案建立。
 35→ *
 36→ * 簡化自 Claude SubagentDetector：
 37→ * - 無 handleEarlyDetection（無 spawn 事件）
 38→ * - 無 handleAgentProgress（無 resume 事件）
 39→ * - 無 handleFallbackDetection（無 toolUseResult）
 40→ * - 無 pendingDescriptions 佇列（無 description 來源）
 41→ */
 42→export class CursorSubagentDetector {
 43→  private knownAgentIds: Set<string>;
 44→  private dirWatcher: FSWatcher | null = null;
 45→  private parentWatcher: FSWatcher | null = null;
 46→  private scanTimer: ReturnType<typeof setTimeout> | null = null;
 47→  private isWatching = false;
 48→  private pendingTimers: Set<ReturnType<typeof setTimeout>> = new Set();
 49→  private stopped = false;
 50→
 51→  constructor(
 52→    private subagentsDir: string,
 53→    private config: {
 54→      output: OutputHandler;
 55→      watcher: WatcherHandler;
 56→      session?: SessionHandler;
 57→      enabled: boolean;
 58→      onNewSubagent?: (agentId: string, subagentPath: string) => void;
 59→    }
 60→  ) {
 61→    this.knownAgentIds = new Set();
 62→  }
 63→
 64→  /**
 65→   * 註冊已知的 subagent（啟動時預填既有 subagent）
 66→   */
 67→  registerExistingAgent(agentId: string, path: string): void {
 68→    this.knownAgentIds.add(agentId);
 69→    // Session 處理（Interactive 模式）
 70→    this.config.session?.addSession?.(
 71→      agentId,
 72→      makeCursorAgentLabel(agentId),
 73→      path
 74→    );
 75→  }
 76→
 77→  /**
 78→   * 啟動 subagents 目錄監控
 79→   */
 80→  startDirectoryWatch(): void {
 81→    if (!this.config.enabled) return;
 82→    if (this.isWatching) return;
 83→
 84→    this.isWatching = true;
 85→    this.tryWatchSubagentsDir();
 86→  }
 87→
 88→  /**
 89→   * 停止所有監控
 90→   */
 91→  stop(): void {
 92→    this.stopped = true;
 93→    this.isWatching = false;
 94→    this.clearScanTimer();
 95→    for (const timer of this.pendingTimers) {
 96→      clearTimeout(timer);
 97→    }
 98→    this.pendingTimers.clear();
 99→    this.dirWatcher?.close();
100→    this.dirWatcher = null;
101→    this.parentWatcher?.close();
102→    this.parentWatcher = null;
103→  }
104→
105→  /**
106→   * 取得已知的 agentId 集合
107→   */
108→  getKnownAgentIds(): Set<string> {
109→    return new Set(this.knownAgentIds);
110→  }
111→
112→  // ============================================================
113→  // Private Methods
114→  // ============================================================
115→
116→  private clearScanTimer(): void {
117→    if (this.scanTimer) {
118→      clearTimeout(this.scanTimer);
119→      this.scanTimer = null;
120→    }
121→  }
122→
123→  private scheduleScan(): void {
124→    if (!this.isWatching) return;
125→    this.clearScanTimer();
126→    this.scanTimer = setTimeout(async () => {
127→      if (!this.isWatching || this.stopped) return;
128→      try {
129→        const newAgentIds = await scanCursorSubagents(
130→          this.subagentsDir,
131→          this.knownAgentIds
132→        );
133→        for (const agentId of newAgentIds) {
134→          if (this.stopped) return;
135→          this.registerNewAgent(agentId);
136→        }
137→      } catch (error) {
138→        this.config.output.error(`Directory scan failed: ${error}`);
139→      }
140→    }, 100);
141→  }
142→
143→  private tryWatchSubagentsDir(): void {
144→    if (!this.isWatching) return;
145→
146→    try {
147→      this.parentWatcher?.close();
148→      this.parentWatcher = null;
149→
150→      this.dirWatcher = watch(this.subagentsDir, () => {
151→        this.scheduleScan();
152→      });
153→      this.dirWatcher.on('error', () => {
154→        this.dirWatcher?.close();
155→        this.dirWatcher = null;
156→      });
157→      // 目錄建立後先掃描一次
158→      this.scheduleScan();
159→    } catch {
160→      // subagents 目錄可能尚未建立，改監控父層目錄
161→      this.watchParentForSubagentsDir();
162→    }
163→  }
164→
165→  private watchParentForSubagentsDir(): void {
166→    if (!this.isWatching) return;
167→    if (this.parentWatcher) return;
168→
169→    const parentDir = join(this.subagentsDir, '..');
170→    try {
171→      this.parentWatcher = watch(parentDir, () => {
172→        this.tryWatchSubagentsDir();
173→      });
174→      this.parentWatcher.on('error', () => {
175→        this.parentWatcher?.close();
176→        this.parentWatcher = null;
177→      });
178→    } catch {
179→      // ignore
180→    }
181→  }
182→
183→  private registerNewAgent(agentId: string): void {
184→    if (this.knownAgentIds.has(agentId)) return;
185→    if (this.stopped) return;
186→
187→    this.knownAgentIds.add(agentId);
188→
189→    const subagentPath = buildCursorSubagentPath(this.subagentsDir, agentId);
190→
191→    // Session 處理（Interactive 模式）
192→    this.config.session?.addSession?.(
193→      agentId,
194→      makeCursorAgentLabel(agentId),
195→      subagentPath
196→    );
197→
198→    if (this.config.enabled) {
199→      this.config.output.warn(`New subagent detected: ${agentId}`);
200→
201→      // 觸發 onNewSubagent 回呼
202→      this.config.onNewSubagent?.(agentId, subagentPath);
203→
204→      // 非阻塞式新增檔案監控
205→      const timer = setTimeout(() => {
206→        this.pendingTimers.delete(timer);
207→        if (!this.isWatching || this.stopped) return;
208→
209→        this.tryAddSubagentFile(subagentPath, agentId);
210→      }, SUBAGENT_FILE_RETRY.initialDelay);
211→      this.pendingTimers.add(timer);
212→    }
213→  }
214→
215→  private async tryAddSubagentFile(
216→    subagentPath: string,
217→    agentId: string
218→  ): Promise<void> {
219→    const config = SUBAGENT_FILE_RETRY;
220→    let retriesLeft = config.maxRetries;
221→
222→    while (retriesLeft > 0) {
223→      if (this.stopped) return;
224→
225→      try {
226→        const file = Bun.file(subagentPath);
227→        if (await file.exists()) {
228→          await this.config.watcher.addFile({
229→            path: subagentPath,
230→            label: makeCursorAgentLabel(agentId),
231→          });
232→          return;
233→        }
234→      } catch (error) {
235→        this.config.output.error(
236→          `Failed to add subagent watcher: ${agentId} - ${error}`
237→        );
238→        return;
239→      }
240→
241→      retriesLeft--;
242→      if (retriesLeft > 0) {
243→        await new Promise((resolve) => setTimeout(resolve, config.retryDelay));
244→      }
245→    }
246→
247→    this.config.output.debug(
248→      `Subagent file not found after retries: ${agentId}`
249→    );
250→  }
251→}
