Perfect! Now I have all the context. Let me create a comprehensive report of the interactive mode architecture and patterns.

## Medium Exploration: Interactive Mode Architecture for Claude & Codex Agents

Based on my analysis of the codebase, here's a detailed breakdown of how interactive mode works for Claude and Codex agents, with minimal code needed to implement Cursor interactive mode.

---

### 1. **Core Components Overview**

#### **SessionManager** (`src/core/session-manager.ts`)
Manages multiple watcher sessions for interactive switching. Key interface:

```typescript
export interface WatcherSession {
  id: string;                    // 'main' or agentId
  label: string;                 // '[MAIN]' or '[a0627b6]'
  path: string;                  // File path
  buffer: string[];              // Output buffer (history)
  isDone: boolean;               // Completion flag
  createdAt: number;             // Timestamp
  displayName?: string;          // Custom title (Claude only)
}

export class SessionManager {
  addSession(id, label, path, displayName?): WatcherSession
  getAllSessions(): WatcherSession[]
  getActiveSession(): WatcherSession | null
  switchNext(): WatcherSession | null
  switchPrev(): WatcherSession | null
  switchTo(id): WatcherSession | null
  handleOutput(label, content): void         // Buffers all, displays active
  flushActiveBuffer(): void                  // Show buffered history
  updateSessionDisplayName(id, displayName): void
  markSessionDone(id): void
  getWatchedFiles(): WatchedFile[]
}
```

Key logic: `handleOutput()` buffers all sessions but **only displays active session**. On switch, `flushActiveBuffer()` replays buffered history.

#### **DisplayController** (`src/interactive/display-controller.ts`)
Terminal UI: persistent status line at bottom, content area above.

```typescript
export class DisplayController {
  init(): void                           // Setup scroll region + status line
  destroy(): void                        // Restore terminal state
  write(content): void                   // Output to content area
  updateStatusLine(sessions, activeIndex): void
  showSwitchMessage(session, historyContent): void
}
```

Status line format: `[3/20] MAIN(50) | [a0627b6](12) | [b1f23c9] (Tab/q)` where `(N)` = buffer size.

#### **Helper Function: `createInteractiveSessionManager`** (lines 647-674 in `src/index.ts`)

Shared by both Claude and Codex interactive modes:

```typescript
function createInteractiveSessionManager(
  displayController: DisplayController
): SessionManager {
  return new SessionManager({
    bufferSize: 1000,
    onOutput: (content, _session) => {
      displayController.write(content);
    },
    onSessionAdded: (session) => {
      displayController.write(chalk.yellow(`New session added: ${session.label}`));
      displayController.updateStatusLine(manager.getAllSessions(), manager.getActiveIndex());
    },
    onSessionSwitched: (session, allSessions) => {
      const historyContent = session.buffer.slice();
      displayController.updateStatusLine(allSessions, manager.getActiveIndex());
      displayController.showSwitchMessage(session, historyContent);
    },
  });
}
```

---

### 2. **Claude Interactive Mode** (`startClaudeInteractiveWatch`, lines 679-935)

**Key Pattern: Stateful parsers per session**

```typescript
async function startClaudeInteractiveWatch(
  sessionFile: SessionFile,
  formatter: Formatter,
  options: CliOptions,
  initialSubagent: SessionFile | null = null
): Promise<void> {
  // TTY check
  if (!process.stdin.isTTY) {
    await startClaudeMultiWatch(sessionFile, formatter, options, initialSubagent);
    return;
  }

  const displayController = new DisplayController({
    persistentStatusLine: true,
    historyLines: 50,
  });

  let sessionManager!: SessionManager;
  let parsers = new Map<string, LineParser>();  // Per-session parsers!
  let multiWatcher: MultiFileWatcher | null = null;
  let detector: SubagentDetector | null = null;
  let currentSessionFile = sessionFile;

  // ========== buildInteractiveState ==========
  const buildInteractiveState = async (
    targetSessionFile: SessionFile,
    initialSubagentFile: SessionFile | null,
    showIntro: boolean
  ): Promise<void> => {
    const subagentsDir = getSubagentsDir(targetSessionFile.path);

    sessionManager = createInteractiveSessionManager(displayController);

    // Main session + subagents
    sessionManager.addSession('main', MAIN_LABEL, targetSessionFile.path, mainTitle);
    const existingAgentIds = await scanForNewSubagents(subagentsDir, new Set());
    const existingSubagentFiles = await buildSubagentFiles(subagentsDir, existingAgentIds);
    for (const { agentId, path } of existingSubagentFiles) {
      sessionManager.addSession(agentId, makeAgentLabel(agentId), path);
    }

    // CREATE INDEPENDENT PARSER FOR EACH SESSION
    parsers = new Map<string, LineParser>();
    for (const session of sessionManager.getAllSessions()) {
      const parserAgent = new ClaudeAgent({ verbose: options.verbose });
      parsers.set(session.label, parserAgent.parser);  // One parser per label!
    }

    const watcher = new MultiFileWatcher();
    multiWatcher = watcher;

    // SubagentDetector with InteractiveSessionHandler
    detector = new SubagentDetector(existingAgentIds, {
      subagentsDir,
      output: new DisplayControllerOutputHandler(displayController),
      watcher: { addFile: (f) => watcher.addFile(f) },
      session: new InteractiveSessionHandler(sessionManager, displayController),
      enabled: true,  // Interactive is always follow
    });
    detector.startDirectoryWatch();
  };

  // ========== startWatcher ==========
  const startWatcher = async (): Promise<void> => {
    const files = sessionManager.getWatchedFiles();

    await multiWatcher.start(files, {
      follow: options.follow,
      pollInterval: options.sleepInterval,
      initialLines: options.lines,
      onLine: createOnLineHandler({
        parsers,  // Pass all parsers
        formatter,
        detector: activeDetector,
        onOutput: (formatted, label) =>
          sessionManager.handleOutput(label, formatted),
        verbose: options.verbose,
        onTitleUpdate: (title) => {
          sessionManager.updateSessionDisplayName('main', title);
          displayController.updateStatusLine(
            sessionManager.getAllSessions(),
            sessionManager.getActiveIndex()
          );
        },
      }),
      onError: (error) => {
        displayController.write(chalk.red(`Error: ${error.message}`));
      },
    });
  };

  // ========== Keyboard Handling ==========
  if (process.stdin.isTTY) {
    process.stdin.setRawMode(true);
    process.stdin.resume();
    process.stdin.setEncoding('utf8');

    process.stdin.on('data', (key: string) => {
      if (key === '\u0003') cleanup();                 // Ctrl+C
      if (key === 'q' || key === 'Q') cleanup();       // q
      if (key === '\t') sessionManager.switchNext();   // Tab
      if (key === '\u001b[Z') sessionManager.switchPrev(); // Shift+Tab
      if (key === 'n' || key === 'N') sessionManager.switchNext();  // n
      if (key === 'p' || key === 'P') sessionManager.switchPrev();  // p
    });
  }

  // ========== Session Switch (Super-Follow) ==========
  const switchToSession = async (nextSessionFile: SessionFile): Promise<void> => {
    detector?.stop();
    multiWatcher?.stop();

    currentSessionFile = nextSessionFile;
    await buildInteractiveState(nextSessionFile, null, false);

    displayController.updateStatusLine(
      sessionManager.getAllSessions(),
      sessionManager.getActiveIndex()
    );
    await startWatcher();

    const nextSessionId = basename(nextSessionFile.path, '.jsonl');
    const switchTitle = await readCustomTitle(nextSessionFile.path);
    const switchTitleSuffix = switchTitle ? ` "${switchTitle}"` : '';
    displayController.write(
      chalk.gray(
        `Switched to latest session: ${nextSessionId}${switchTitleSuffix}`
      )
    );
  };

  const superFollow = createSuperFollowController({
    projectDir: lockedProjectDir,
    getCurrentPath: () => currentSessionFile.path,
    onSwitch: switchToSession,
    autoSwitch: options.autoSwitch,
    findLatestInProject: findLatestMainSessionInProject,
  });

  superFollow.start();

  // ========== Initialization & Event Handlers ==========
  await buildInteractiveState(currentSessionFile, initialSubagent, true);
  displayController.init();
  displayController.updateStatusLine(
    sessionManager.getAllSessions(),
    sessionManager.getActiveIndex()
  );
  await startWatcher();

  const cleanup = (): void => {
    superFollow.stop();
    displayController.destroy();
    detector?.stop();
    if (process.stdin.isTTY) process.stdin.setRawMode(false);
    multiWatcher?.stop();
  };

  process.on('SIGINT', () => {
    cleanup();
    process.exit(0);
  });

  displayController.write(
    chalk.gray('Watching for changes... (Tab to switch, q to quit)')
  );
}
```

**Claude-specific considerations:**
- **Stateful parser per session**: Claude's `LineParser` maintains state (`processedMessageIds` in tool parsing). Each session needs its own parser instance.
- **Custom title support**: Reads from `/rename` command in JSONL, updates `displayName` in `onTitleUpdate` callback.
- **InteractiveSessionHandler** wraps `SessionManager` + `DisplayController` for `SubagentDetector` integration.

---

### 3. **Codex Interactive Mode** (`startCodexInteractiveWatch`, lines 940-1173)

**Key Pattern: Shared stateless parser + let-based handler closure**

```typescript
async function startCodexInteractiveWatch(
  sessionFile: SessionFile,
  formatter: Formatter,
  options: CliOptions
): Promise<void> {
  // TTY check
  if (!process.stdin.isTTY) {
    await startCodexMultiWatch(sessionFile, formatter, options);
    return;
  }

  const codexAgent = new CodexAgent({ verbose: options.verbose });
  const projectInfo = codexAgent.finder.getProjectInfo
    ? await codexAgent.finder.getProjectInfo(sessionFile.path)
    : null;
  const projectDir = projectInfo?.projectDir ?? dirname(sessionFile.path);

  const displayController = new DisplayController({
    persistentStatusLine: true,
    historyLines: 50,
  });

  let sessionManager!: SessionManager;
  let multiWatcher: MultiFileWatcher | null = null;
  let detector: CodexSubagentDetector | null = null;
  let currentSessionFile = sessionFile;

  // Codex: Shared stateless parser
  const sharedParser = codexAgent.parser;

  // detectionHandler is a let variable updated in buildInteractiveState
  // This allows switchToSession to update the detector reference
  let detectionHandler: (line: string, label: string) => void = () => {};

  // ========== buildInteractiveState ==========
  const buildInteractiveState = async (
    targetSessionFile: SessionFile,
    showIntro: boolean
  ): Promise<void> => {
    const dateDirLocal = dirname(targetSessionFile.path);

    sessionManager = createInteractiveSessionManager(displayController);
    sessionManager.addSession('main', MAIN_LABEL, targetSessionFile.path);

    // Codex: scan using extractCodexSubagentIds (parses main session JSONL)
    const existingIds = await extractCodexSubagentIds(targetSessionFile.path);
    const existingSubFiles = await buildCodexSubagentFiles(dateDirLocal, existingIds);

    for (const f of existingSubFiles) {
      const agentId = extractUUIDFromPath(f.path);
      const label = makeCodexAgentLabel(agentId);
      sessionManager.addSession(agentId, label, f.path);
    }

    const watcher = new MultiFileWatcher();
    multiWatcher = watcher;

    detector = new CodexSubagentDetector(existingIds, {
      sessionDateDir: dateDirLocal,
      output: new DisplayControllerOutputHandler(displayController),
      watcher: { addFile: (f) => watcher.addFile(f) },
      enabled: true,
      onNewSubagent: (agentId, path, _description) => {
        const label = makeCodexAgentLabel(agentId);
        sessionManager.addSession(agentId, label, path);
        displayController.updateStatusLine(
          sessionManager.getAllSessions(),
          sessionManager.getActiveIndex()
        );
      },
      onSubagentDone: (agentId) => {
        sessionManager.markSessionDone(agentId);
        displayController.write(chalk.gray(`[subagent] ${agentId.slice(0, 8)} done`));
        displayController.updateStatusLine(
          sessionManager.getAllSessions(),
          sessionManager.getActiveIndex()
        );
      },
    });

    // Prefill existing agent paths (for resume_agent event)
    for (const f of existingSubFiles) {
      detector.registerExistingAgent(extractUUIDFromPath(f.path), f.path);
    }

    // UPDATE detectionHandler (let variable) to point to new detector
    detectionHandler = createCodexOnLineHandler(detector);
  };

  // ========== startWatcher ==========
  const startWatcher = async (): Promise<void> => {
    const files = sessionManager.getWatchedFiles();

    await multiWatcher.start(files, {
      follow: true,  // Interactive is always follow
      pollInterval: options.sleepInterval,
      initialLines: options.lines,
      onLine: (line: string, label: string) => {
        // detectionHandler points to latest detector via let variable
        detectionHandler(line, label);

        // Single shared parser for all sessions
        const parsed = sharedParser.parse(line);
        if (!parsed) return;
        parsed.sourceLabel = label;
        sessionManager.handleOutput(label, formatter.format(parsed));
      },
      onError: (error) => {
        displayController.write(chalk.red(`Error: ${error.message}`));
      },
    });
  };

  // ========== Keyboard Handling (identical to Claude) ==========
  if (process.stdin.isTTY) {
    process.stdin.setRawMode(true);
    process.stdin.resume();
    process.stdin.setEncoding('utf8');

    process.stdin.on('data', (key: string) => {
      if (key === '\u0003') cleanup();
      if (key === 'q' || key === 'Q') cleanup();
      if (key === '\t') sessionManager.switchNext();
      if (key === '\u001b[Z') sessionManager.switchPrev();
      if (key === 'n' || key === 'N') sessionManager.switchNext();
      if (key === 'p' || key === 'P') sessionManager.switchPrev();
    });
  }

  // ========== Session Switch (Super-Follow) ==========
  const switchToSession = async (nextFile: SessionFile): Promise<void> => {
    detector?.stop();
    multiWatcher?.stop();

    currentSessionFile = nextFile;
    await buildInteractiveState(nextFile, false);

    displayController.updateStatusLine(
      sessionManager.getAllSessions(),
      sessionManager.getActiveIndex()
