Shared by both Claude and Codex interactive modes:

```typescript
function createInteractiveSessionManager(
  displayController: DisplayController
): SessionManager {
  return new SessionManager({
    bufferSize: 1000,
    onOutput: (content, _session) => {
      displayController.write(content);
    },
    onSessionAdded: (session) => {
      displayController.write(chalk.yellow(`New session added: ${session.label}`));
      displayController.updateStatusLine(manager.getAllSessions(), manager.getActiveIndex());
    },
    onSessionSwitched: (session, allSessions) => {
      const historyContent = session.buffer.slice();
      displayController.updateStatusLine(allSessions, manager.getActiveIndex());
      displayController.showSwitchMessage(session, historyContent);
    },
  });
}
