  // ========== Keyboard Handling ==========
  if (process.stdin.isTTY) {
    process.stdin.setRawMode(true);
    process.stdin.resume();
    process.stdin.setEncoding('utf8');

    process.stdin.on('data', (key: string) => {
      if (key === '\u0003') cleanup();                 // Ctrl+C
      if (key === 'q' || key === 'Q') cleanup();       // q
      if (key === '\t') sessionManager.switchNext();   // Tab
      if (key === '\u001b[Z') sessionManager.switchPrev(); // Shift+Tab
      if (key === 'n' || key === 'N') sessionManager.switchNext();  // n
      if (key === 'p' || key === 'P') sessionManager.switchPrev();  // p
    });
  }

  // ========== Session Switch (Super-Follow) ==========
