  // detectionHandler is a let variable updated in buildInteractiveState
  // This allows switchToSession to update the detector reference
  let detectionHandler: (line: string, label: string) => void = () => {};

  // ========== buildInteractiveState ==========
  const buildInteractiveState = async (
    targetSessionFile: SessionFile,
    showIntro: boolean
  ): Promise<void> => {
