 69→/**
 70→ * 解析 CLI 參數
 71→ */
 72→export function parseArgs(args: string[]): CliOptions {
 73→  const program = createProgram();
 74→  program.parse(args);
 75→
 76→  const agentTypeArg = program.args[0];
 77→  const sessionIdArg = program.args[1];
 78→  const opts = program.opts();
 79→
 80→  // 驗證 agent 類型
 81→  if (
 82→    agentTypeArg !== 'codex' &&
 83→    agentTypeArg !== 'claude' &&
 84→    agentTypeArg !== 'gemini' &&
 85→    agentTypeArg !== 'cursor'
 86→  ) {
 87→    console.error(
 88→      `Error: Invalid agent type "${agentTypeArg}". Use "codex", "claude", "gemini", or "cursor".`
 89→    );
 90→    process.exit(1);
 91→  }
 92→
 93→  // subagent 選項對 claude、codex、cursor 有效
 94→  if (
 95→    opts.subagent !== undefined &&
 96→    agentTypeArg !== 'claude' &&
 97→    agentTypeArg !== 'codex' &&
 98→    agentTypeArg !== 'cursor'
 99→  ) {
100→    console.error(
101→      'Error: --subagent option is only available for "claude", "codex", and "cursor" agent types.'
102→    );
103→    process.exit(1);
104→  }
105→
106→  // --all preset 選項對 claude、codex、cursor 有效（需要在展開前驗證）
107→  if (
108→    opts.all &&
109→    agentTypeArg !== 'claude' &&
110→    agentTypeArg !== 'codex' &&
111→    agentTypeArg !== 'cursor'
112→  ) {
113→    console.error(
114→      'Error: --all option is only available for "claude", "codex", and "cursor" agent types.'
115→    );
116→    process.exit(1);
117→  }
118→
119→  // 展開 --all preset（只在選項未明確設定時才覆蓋）
120→  if (opts.all) {
121→    if (opts.verbose === undefined) opts.verbose = true;
122→    if (opts.withSubagents === undefined) opts.withSubagents = true;
123→    if (opts.autoSwitch === undefined) opts.autoSwitch = true;
124→  }
125→
126→  // 將 undefined 轉換為 false（對於非 preset 選項）
127→  const finalVerbose = opts.verbose ?? false;
128→  const finalInteractive = opts.interactive ?? false;
129→  let finalWithSubagents = opts.withSubagents ?? false;
130→  const finalAutoSwitch = opts.autoSwitch ?? false;
131→  const finalPane = opts.pane ?? false;
132→
133→  // interactive 選項對 claude 和 codex 有效
134→  if (
135→    finalInteractive &&
136→    agentTypeArg !== 'claude' &&
137→    agentTypeArg !== 'codex'
138→  ) {
139→    console.error(
140→      'Error: --interactive option is only available for "claude" and "codex" agent types.'
141→    );
142→    process.exit(1);
143→  }
144→
145→  // interactive 和 subagent 互斥
146→  if (finalInteractive && opts.subagent !== undefined) {
147→    console.error(
148→      'Error: --interactive and --subagent options cannot be used together.'
149→    );
150→    process.exit(1);
151→  }
152→
153→  // interactive 需要 follow 模式
154→  if (finalInteractive && !opts.follow) {
155→    console.error(
156→      'Error: --interactive requires --follow mode (cannot use with --no-follow).'
157→    );
158→    process.exit(1);
159→  }
160→
161→  // pane 選項對 claude、codex、cursor 有效
162→  if (
163→    finalPane &&
164→    agentTypeArg !== 'claude' &&
165→    agentTypeArg !== 'codex' &&
166→    agentTypeArg !== 'cursor'
167→  ) {
168→    console.error(
169→      'Error: --pane option is only available for "claude", "codex", and "cursor" agent types.'
170→    );
171→    process.exit(1);
172→  }
173→
174→  // pane 和 interactive 互斥
175→  if (finalPane && finalInteractive) {
176→    console.error(
177→      'Error: --pane and --interactive options cannot be used together.'
178→    );
179→    process.exit(1);
180→  }
181→
182→  // pane 和 subagent 互斥（pane 在多檔案監控模式，subagent 在單檔案模式）
183→  if (finalPane && opts.subagent !== undefined) {
184→    console.error(
185→      'Error: --pane and --subagent options cannot be used together.'
186→    );
187→    process.exit(1);
188→  }
189→
190→  // pane 需要 follow 模式
191→  if (finalPane && !opts.follow) {
192→    console.error(
193→      'Error: --pane requires --follow mode (cannot use with --no-follow).'
194→    );
195→    process.exit(1);
196→  }
197→
198→  // pane 自動啟用 withSubagents（subagent 偵測必須啟用才能開 pane）
199→  if (finalPane && !finalWithSubagents) {
200→    finalWithSubagents = true;
201→  }
202→
203→  // withSubagents 選項對 claude、codex、cursor 有效
204→  if (
205→    finalWithSubagents &&
206→    agentTypeArg !== 'claude' &&
207→    agentTypeArg !== 'codex' &&
208→    agentTypeArg !== 'cursor'
209→  ) {
210→    console.error(
211→      'Error: --with-subagents option is only available for "claude", "codex", and "cursor" agent types.'
212→    );
213→    process.exit(1);
214→  }
215→
216→  // sleepInterval 驗證
217→  if (
218→    opts.sleepInterval !== undefined &&
219→    (opts.sleepInterval < 100 || opts.sleepInterval > 60000)
220→  ) {
221→    console.error(
222→      'Error: --sleep-interval must be between 100 and 60000 milliseconds.'
223→    );
224→    process.exit(1);
225→  }
226→
227→  // lines 驗證
228→  if (opts.lines !== undefined && Number.isNaN(opts.lines)) {
229→    console.error('Error: --lines must be a valid number.');
230→    process.exit(1);
231→  }
232→
233→  return {
234→    agentType: agentTypeArg as AgentType,
235→    raw: opts.raw,
236→    project: opts.project,
237→    follow: opts.follow,
238→    verbose: finalVerbose,
239→    quiet: opts.quiet ?? false,
240→    sleepInterval: opts.sleepInterval ?? 500,
241→    lines: opts.lines,
242→    subagent: opts.subagent,
243→    interactive: finalInteractive,
244→    withSubagents: finalWithSubagents,
245→    autoSwitch: finalAutoSwitch,
246→    pane: finalPane,
247→    sessionId: sessionIdArg,
248→  };
249→}
