 66→
 67→/**
 68→ * 掃描 subagents 目錄，找出尚未被監控的新 subagent 檔案
 69→ * @param subagentsDir subagents 目錄路徑
 70→ * @param knownAgentIds 已知的 agentId 集合
 71→ * @returns 新發現的 agentId 陣列
 72→ */
 73→export async function scanCursorSubagents(
 74→  subagentsDir: string,
 75→  knownAgentIds: Set<string>
 76→): Promise<string[]> {
 77→  const newAgentIds: string[] = [];
 78→
 79→  try {
 80→    const glob = new Glob('*.jsonl');
 81→    for await (const file of glob.scan({ cwd: subagentsDir })) {
 82→      const match = file.match(UUID_FILENAME_REGEX);
 83→      if (match && match[1]) {
 84→        const agentId = match[1];
 85→        if (!knownAgentIds.has(agentId)) {
 86→          newAgentIds.push(agentId);
 87→        }
 88→      }
 89→    }
 90→  } catch {
 91→    // subagents 目錄不存在或無法存取時靜默忽略
 92→  }
 93→
 94→  return newAgentIds;
 95→}
 96→
 97→/**
 98→ * 建立 subagent 檔案列表（含 stat 資訊）
 99→ * @param subagentsDir subagents 目錄路徑
100→ * @param agentIds 已知的 agentId 陣列
101→ * @returns SessionFile 陣列，按 birthtime 排序（舊到新）
102→ */
103→export async function buildCursorSubagentFiles(
104→  subagentsDir: string,
105→  agentIds: string[]
106→): Promise<Array<{ agentId: string; path: string; mtime: Date }>> {
107→  const results: Array<{ agentId: string; path: string; mtime: Date }> = [];
108→
109→  const statPromises = agentIds.map(async (agentId) => {
110→    const filePath = buildCursorSubagentPath(subagentsDir, agentId);
111→    try {
112→      const stats = await stat(filePath);
113→      return { agentId, path: filePath, mtime: stats.mtime };
114→    } catch {
115→      return null;
116→    }
117→  });
118→
119→  const settled = await Promise.all(statPromises);
120→  for (const result of settled) {
121→    if (result) results.push(result);
122→  }
123→
124→  // 按 mtime 排序（舊到新）
125→  results.sort((a, b) => a.mtime.getTime() - b.mtime.getTime());
126→  return results;
127→}
